insert into public.knowledge_entries
  (type, title, body, category, tags, source_type, source_id, source_title, status, confidence, created_by)
values
('term','간편심사','유병자 또는 고령자가 일반 보험의 복잡한 고지의무 대신 축소된 질문 항목으로 보험에 가입하는 심사 방식. 전통적으로 최근 3개월 이내 입원·수술·추가 검사 소견, 최근 2년 이내 입원·수술, 최근 5년 이내 암 진단·치료 여부 등을 묻는 ''3·2·5'' 형태가 대표적이었으나, 2024년 7월 금감원 보도자료 기준으로 상품별로 3·5·5, 3·10·10 등 다양한 구성이 출시되어 있으며 회사·상품별로 항목 수와 기간이 상이하다. 표준체보다 보험료가 높고, 고지의무 자체가 면제되는 것이 아니므로 위반 시 계약 해지 등 불이익이 동일하게 적용된다.','인수',array['간편심사','유병자보험','간편보험','3-2-5고지','언더라이팅'],'cycle2_mined','cycle2_mined','금감원 보도자료 2024.7.2. (상품심사판매분석국 보장상품팀) / 보험업감독규정 (금융위원회 고시, 국가법령정보센터)','ai_draft','medium','admin'),
('term','유병자보험','만성질환(고혈압·당뇨 등)을 앓고 있거나 과거 병력이 있는 유병자가 간편심사를 통해 가입할 수 있는 보험 상품군. 표준 고지의무 항목을 축소하고 해당 위험을 반영한 할증보험료를 적용하여 인수한다. 고지의무 간소화 유형(간편심사보험)·특화 질환 유형(고혈압·당뇨 특화)·무심사 유형으로 세분화된다.','인수',array['유병자보험','간편보험','만성질환','고혈압당뇨보험','표준미달체'],'cycle2_mined','cycle2_mined','보험업감독규정 (금융위원회 고시, 국가법령정보센터) / 보험연구원 연구보고서 nre2018-05','ai_draft','high','admin'),
('term','전기간부담보','보험계약 기간 전체에 걸쳐 특정 신체 부위 또는 질병을 보장 범위에서 제외하는 조건부 인수 방식. 한시부담보(일정 기간만 제외)와 구별되며, 청약일로부터 5년 이내에 해당 부위·질병으로 추가 진단(단순 건강검진 제외) 또는 치료를 받은 사실이 없으면 5년 경과 후 보장으로 전환될 수 있다. 생명·손해보험 약관 모두에 적용된다.','인수',array['전기간부담보','부담보해제','조건부인수','특정부위제외','보장제한'],'cycle2_mined','cycle2_mined','생명보험 표준약관 (보험업감독업무시행세칙 별표15, 금감원) / 금감원 소비자유의사항 (fss.or.kr)','ai_draft','high','admin'),
('term','한시부담보','보험계약 체결 시 특정 신체 부위나 질병에 대해 1년·2년·3년 등 일정 기간 동안만 보장을 제외하는 조건부 인수 방식. 기간이 경과하고 해당 부위·질병으로 추가 치료가 없으면 보장이 자동 복원되는 것이 일반적이다. 전기간부담보보다 계약자에게 유리한 조건으로, 표준미달체의 인수 방법 중 하나이다.','인수',array['한시부담보','기간부담보','조건부계약','부담보','표준미달체인수'],'cycle2_mined','cycle2_mined','생명보험 표준약관 및 해설 (생명보험협회 자격시험센터 공개 자료, exam.insure.or.kr)','ai_draft','high','admin'),
('term','감액인수','표준미달체 피보험자에 대해 계약 체결 시 약정된 일정 기간(삭감 기간) 동안 보험금을 삭감하여 지급하는 조건부 인수 방식. 삭감 기간과 삭감 비율을 사전에 약정하며, 삭감 기간이 지나면 이후 보험금은 정상 지급된다. 할증·부담보와 함께 표준미달체 인수의 주요 3종 방법 중 하나이다. 보험료 수준은 회사 및 상품에 따라 표준 보험료를 적용하거나 일부 조정하는 경우가 있어 반드시 약관을 확인해야 한다.','인수',array['감액인수','보험금삭감','표준미달체','조건부계약','삭감기간'],'cycle2_mined','cycle2_mined','생명보험 표준약관 (보험업감독업무시행세칙 별표15, 금감원) / 생명보험협회 자격시험센터 공개 자료 (exam.insure.or.kr 2026 생명보험이란 무엇인가)','ai_draft','medium','admin'),
('term','우량체(건강체)','일반 표준체보다 건강 수준이 우수하여 보험료 할인을 적용받는 피보험자 등급. 대표적인 판정 기준으로 비흡연(직전 1년 무흡연), BMI 20.0~27.9, 정상 혈압(수축기 110~135mmHg) 등이 활용된다. 세부 기준은 보험회사별로 상이할 수 있으며, 보험회사별 건강진단을 통해 확정된다. 표준체 대비 3~20% 내외의 보험료 할인이 적용되는 것이 일반적이다.','인수',array['우량체','건강체','비흡연자할인','우량체할인','BMI기준'],'cycle2_mined','cycle2_mined','손해보험협회 건강관련 할인제도 운영현황 비교공시 (kpub.knia.or.kr) / 보험개발원 민영건강보험 언더라이팅 선진화 방안 (연구보고서 2003-1)','ai_draft','medium','admin'),
('term','직업위험급수','피보험자의 직업·직무에 따른 상해 위험 수준을 등급화한 분류 체계. 보험개발원이 직업별 사고 통계를 기반으로 참조요율(기준표)을 산출하고, 각 보험회사는 이를 반영해 1급(비위험·사무직 등)·2급(중위험·외근직 등)·3급(고위험·건설·소방 등)으로 구분하여 보험료와 인수 여부를 결정한다. 일부 회사는 4급 이상을 추가 운용하기도 한다. 직업 또는 직무 변경 시 통지 의무(상법 제652조)가 발생한다.','인수',array['직업위험급수','직업급수','상해위험등급','직종분류','보험개발원'],'cycle2_mined','cycle2_mined','보험개발원 직업·위험등급 분류표 (각사 공시 자료) / 상법 제652조 (국가법령정보센터)','ai_draft','high','admin'),
('term','위험변경증가 통지의무','보험기간 중 보험계약자 또는 피보험자가 사고 발생 위험이 현저히 변경·증가된 사실을 안 때에는 지체 없이 보험자에게 통지해야 하는 법적 의무. 상법 제652조에 규정되어 있으며, 통지를 해태(게을리)한 경우 보험자는 그 사실을 안 날로부터 1개월 이내에 계약을 해지하거나 보험료 증액을 청구할 수 있다. 직업·직무 변경이 대표적 통지 사유이다.','계약',array['위험변경증가','통지의무','직업변경','상법652조','계약해지'],'cycle2_mined','cycle2_mined','상법 제652조 (위험변경증가의 통지와 계약해지, 국가법령정보센터) / 찾기쉬운 생활법령정보 (easylaw.go.kr) / 대법원 2024.11.28. 선고 2022다238633 판결','ai_draft','high','admin'),
('term','계약적부확인','보험회사가 계약 성립 전·후에 피보험자의 건강 상태, 직업, 병력 등 고지 내용을 임직원 또는 위촉 의사 등을 통해 직접 확인하는 절차. 계약자 간 형평성 유지 및 보험금 지급 분쟁 예방을 목적으로 하며, 확인 결과에 따라 계약 해지 등의 조치를 취할 수 있다. 보험업법 및 보험업감독규정에 근거한다.','인수',array['계약적부확인','적부조사','고지내용확인','인수심사','언더라이팅'],'cycle2_mined','cycle2_mined','보험업감독규정 (금융위원회 고시, 국가법령정보센터) / 보험업법 (국가법령정보센터)','ai_draft','high','admin'),
('term','적부조사','보험 청약 접수 후 또는 계약 성립 후 보험회사가 보험목적물(피보험자의 신체·재산)의 실제 상태, 위험 요소, 고지 내용의 정확성 등을 현장에서 직접 확인하는 조사 활동. 의심 계약이나 고액 계약에서 주로 수행하며, 모럴해저드 및 역선택 방지가 핵심 목적이다. 계약적부확인과 혼용되며, 보험업법령에 근거한다.','인수',array['적부조사','계약적부','현장조사','고액계약','모럴해저드방지'],'cycle2_mined','cycle2_mined','보험업법 및 보험업감독규정 (국가법령정보센터) / 보험사기방지 특별법 (국가법령정보센터)','ai_draft','high','admin'),
('term','재정심사','보험 청약 시 피보험자의 소득·재산 수준과 보험가입금액의 적정성을 비교·심사하는 언더라이팅 절차. 보험금액이 소득·재산에 비해 과도할 경우 모럴해저드(보험사기) 위험이 높아지므로, 생명보험협회·손해보험협회가 제정한 「중복·과다 보험가입 방지 인수심사 가이드라인」(2023년 3분기 시행)에 따라 고위험 청약건에 강화된 재정심사를 적용한다.','인수',array['재정심사','보험가입한도','과다보험방지','모럴해저드','언더라이팅'],'cycle2_mined','cycle2_mined','중복·과다 보험가입 방지 인수심사 가이드라인 (생명보험협회·손해보험협회, 2023년 3분기 시행) / 금융위원회 보도자료 (fsc.go.kr)','ai_draft','high','admin'),
('term','모럴해저드(보험에서의)','보험 계약 체결 후 보험금 취득을 목적으로 피보험자 또는 계약자가 고의로 사고를 유발하거나 손해를 과장하는 도덕적 위험. 계약 전 단계에서 자신의 불량한 위험을 숨기고 가입하려는 역선택(adverse selection)과 구분된다. 보험회사는 재정심사·적부조사·계약적부확인 등으로 사전 방지하며, 보험사기방지 특별법(국가법령정보센터)이 법적 제재 근거를 제공한다.','인수',array['모럴해저드','도덕적위험','보험사기','역선택방지','언더라이팅'],'cycle2_mined','cycle2_mined','보험사기방지 특별법 (국가법령정보센터) / 기획재정부 시사경제용어사전 (moef.go.kr) / 찾기쉬운 생활법령정보 보험사기 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','역선택(언더라이팅)','보험가입 시 위험 수준이 높은 사람이 낮은 보험료를 이용하기 위해 적극적으로 보험에 가입하고, 건강한 사람은 가입을 기피하는 현상. 정보 비대칭에서 발생하며, 보험료 상승과 보험 시장 왜곡을 초래한다. 보험회사는 엄격한 고지의무·건강진단 의무·직업·취미 질문 등 인수심사를 통해 역선택을 방지한다.','인수',array['역선택','정보비대칭','언더라이팅','고지의무','인수심사','adverse selection'],'cycle2_mined','cycle2_mined','KDI 경제교육·정보센터 도덕적 해이와 역선택 학습 영상 (eiec.kdi.re.kr) / 보험연구원 보험사기 연구보고서 RE9906 (kiri.or.kr)','ai_draft','high','admin'),
('term','임의재보험','원보험회사(출재사)가 재보험이 필요한 개별 보험계약 단위별로 재보험자에게 인수 여부를 제의하고, 재보험자가 해당 물건을 검토해 인수 여부를 자유롭게 결정하는 재보험 형태. 특약재보험(자동인수)과 달리 건별로 협의가 필요하며, 주로 대형 또는 특수 위험 계약에 활용된다. 보험업감독규정 별표 28의1 재보험관리기준 및 보험연구원 재보험 연구보고서(nre2019-1212)에서 관련 기준을 확인할 수 있다.','계약',array['임의재보험','재보험','Facultative','대형위험','재보험인수'],'cycle2_mined','cycle2_mined','보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 보험업감독규정 별표 28의1 재보험관리기준 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','특약재보험','원보험회사와 재보험회사가 사전에 특약(Treaty)을 체결하고, 약정된 조건에 해당하는 계약은 자동으로 출재·인수되는 재보험 방식. 임의재보험과 달리 건별 협의 없이 약정 기간 동안 자동 처리되며, 비례재보험과 비비례재보험으로 세분화된다. 보험회사의 위험 분산과 대규모 손해에 대한 지급 능력 확보를 위해 활용한다.','계약',array['특약재보험','Treaty재보험','자동인수','비례재보험','위험분산'],'cycle2_mined','cycle2_mined','보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 보험업감독규정 별표 28의1 재보험관리기준 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','비례재보험','보험가입금액에 대해 원보험회사(출재사)와 재보험회사(수재사)가 미리 정한 비율로 책임과 보험료를 배분하는 재보험 방식. 발생 손해액도 동일 비율로 부담한다. 초과손해액재보험(비비례재보험)과 달리 손해 발생 규모와 관계없이 비율로 배분되므로 예측 가능성이 높다. 생명보험 장기계약에서 주로 활용된다.','계약',array['비례재보험','ProRata재보험','재보험','책임배분','보험료배분'],'cycle2_mined','cycle2_mined','보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)','ai_draft','high','admin'),
('term','초과손해액재보험','보험사고 발생 시 손해액 중 원보험회사가 미리 약정한 보유한도(자기보유액)를 초과하는 부분만 재보험자가 보상하는 비비례재보험 방식. ''Excess of Loss Reinsurance(XL)''라고도 하며, 대규모 재해·사망 등 거대 위험에 대비해 원보험회사의 손실 상한을 제한하는 기능을 한다. KIRI 재보험 연구보고서(nre2019-1212)에서 정의를 확인할 수 있다.','계약',array['초과손해액재보험','XL재보험','비비례재보험','자기보유액','재보험'],'cycle2_mined','cycle2_mined','보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)','ai_draft','high','admin'),
('term','자기보유한도(보유한도)','보험회사가 재보험에 출재하지 않고 자체적으로 감수하는 위험의 최대 금액. 이 한도를 초과하는 부분은 재보험으로 전가된다. 금융감독원 보험업감독규정(별표 28의1 재보험관리기준)에서 보험회사는 건전한 재보험 관리 기준을 수립·운영하도록 규정하며, 적정 보유한도 설정은 지급 여력 관리의 핵심이다.','계약',array['보유한도','자기보유','재보험','위험분산','지급여력'],'cycle2_mined','cycle2_mined','보험업감독규정 별표 28의1 재보험관리기준 (국가법령정보센터 law.go.kr) / 보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr)','ai_draft','high','admin'),
('term','출재','원보험회사(출재사)가 인수한 보험 위험의 전부 또는 일부를 재보험자에게 이전하는 행위. 이때 원보험회사가 재보험자에게 지급하는 보험료를 출재보험료라 한다. 보험연구원 재보험 연구보고서(nre2019-1212) 및 IFRS17 관련 자료에서 출재 개념과 회계 처리를 확인할 수 있다.','계약',array['출재','출재보험료','재보험','위험이전','원보험사'],'cycle2_mined','cycle2_mined','보험연구원 재보험 연구보고서 nre2019-1212 (kiri.or.kr) / 보험연구원 IFRS17 재보험 출재 자료 (kiri.or.kr)','ai_draft','medium','admin'),
('term','가입한도(보험가입한도)','보험회사가 특정 피보험자에 대해 인수할 수 있는 최대 보험가입금액. 피보험자의 소득·재산, 기존 가입 계약, 직업위험급수, 재보험 수재 가능 한도 등을 종합적으로 고려해 설정한다. 중복·과다 보험가입 방지 인수심사 가이드라인(생·손보협회, 2023년 제정)에 따라 강화된 재정심사를 통해 관리된다.','인수',array['가입한도','보험가입금액한도','인수한도','재정심사','과다보험방지'],'cycle2_mined','cycle2_mined','중복·과다 보험가입 방지 인수심사 가이드라인 제정 공고 (손해보험협회·생명보험협회, 2023, knia.or.kr) / 보험업법 제53조 (국가법령정보센터)','ai_draft','high','admin'),
('term','건강진단의무','일정 금액 이상의 보험가입금액에 대해 보험회사가 피보험자에게 요구하는 신체검사 의무. 생명보험의 경우 가입금액·연령 기준에 따라 기본 진단 항목에서 정밀 진단까지 단계별로 요구되며, 진단 결과에 따라 표준 인수·조건부 인수·인수 거절이 결정된다. 생명보험 표준약관(보험업감독업무시행세칙 별표 15) 및 각 보험회사의 인수기준에 근거한다.','인수',array['건강진단','신체검사','고액보험','인수심사','생명보험'],'cycle2_mined','cycle2_mined','생명보험 표준약관 (보험업감독업무시행세칙 별표 15, 금감원 fss.or.kr) / 생명보험협회 자율규제 규정 (klia.or.kr)','ai_draft','high','admin'),
('term','도덕적 위험(보험 인수)','언더라이팅 관점에서 피보험자의 성격, 행동 양식, 생활 습관, 재정 상태 등 주관적·심리적 요인이 보험사고 발생 가능성에 미치는 위험. 환경적 위험(직업·주거지역 등 객관적 요인)과 구별되며, 재정심사·계약적부확인·적부조사를 통해 평가한다. 가입 목적이 불순하거나 보험료 납부 능력이 없는 경우 도덕적 위험이 높은 것으로 판단한다.','인수',array['도덕적위험','주관적위험','언더라이팅','보험사기위험','인수심사'],'cycle2_mined','cycle2_mined','보험연구원(구 보험개발원 보험연구소) 민영건강보험 언더라이팅 선진화 방안 연구보고서 re2003-01 (kiri.or.kr)','ai_draft','high','admin'),
('term','환경적 위험(보험 인수)','보험 인수심사에서 피보험자의 직업, 거주지역, 근무 환경 등 외부적·객관적 조건에서 비롯되는 위험 요인. 직업위험급수, 취미 위험등급 등으로 계량화되며, 도덕적 위험(주관적·심리적 요인)과 함께 전체 위험 평가를 구성한다. 환경적 위험 수준에 따라 할증 보험료 부과 또는 특정 담보 제한 등 조건부 인수가 결정된다.','인수',array['환경적위험','객관적위험','언더라이팅','직업위험','취미위험'],'cycle2_mined','cycle2_mined','보험연구원(구 보험개발원 보험연구소) 민영건강보험 언더라이팅 선진화 방안 연구보고서 re2003-01 (kiri.or.kr)','ai_draft','medium','admin'),
('term','취미위험등급','스카이다이빙·암벽등반·패러글라이딩 등 고위험 레저·스포츠 활동을 위험 수준에 따라 등급화한 분류 체계. 보험 청약 시 고지 대상이 되며, 위험 등급에 따라 상해보험 등의 인수 거절 또는 할증보험료가 적용된다. 각 보험회사는 보험개발원 직업·위험등급 분류표를 기준으로 사의 분류표를 작성하여 공시한다.','인수',array['취미위험등급','레저위험','고위험스포츠','직업위험등급','상해보험인수'],'cycle2_mined','cycle2_mined','직업 및 위험등급 분류표 (손해보험협회 위험직군 가입현황 공시, kpub.knia.or.kr) / 보험개발원 직업등급표','ai_draft','high','admin'),
('term','보험사기방지 특별법','보험계약자 등이 보험금을 취득할 목적으로 보험사고 발생·원인·내용에 관해 보험회사를 기망하는 행위를 처벌하고 예방하기 위해 제정된 특별법. 제8조(보험사기죄)에 따라 10년 이하의 징역 또는 5천만원 이하의 벌금에 처하며, 제1항 제1호의 경우 징역형과 벌금형을 병과할 수 있다. 제9조에 따라 상습범은 정한 형의 2분의 1까지 가중하며, 제11조에 따라 이득액이 5억원 이상이면 이득액 규모에 따라 3년 이상의 유기징역 또는 무기·5년 이상의 징역으로 가중처벌한다. 2016년 시행 후 수차례 개정되었으며, 최신 개정은 2024년 8월 14일 시행되었다.','보장',array['보험사기방지특별법','보험사기','보험범죄','상습가중처벌','금감원신고'],'cycle2_mined','cycle2_mined','보험사기방지 특별법 제8조·제9조·제11조 (국가법령정보센터, law.go.kr/lsInfoP.do?lsiSeq=260401&efYd=20240814)','ai_draft','medium','admin'),
('term','계약전환','기존 보험계약을 소멸시키고 동일 보험회사의 다른 보험계약으로 전환하는 제도. 전환 시 피보험자의 현재 건강 상태에 대한 재심사(인수심사) 없이 기존 계약의 피보험 상태를 승계하는 것이 원칙이며, 이 점이 새로운 청약(재가입)과 다르다. 생명보험 표준약관 및 보험업감독규정에서 전환계약의 절차와 계약자 보호 요건을 규정한다.','계약',array['계약전환','전환계약','전환심사','보험계약변경','고지의무면제'],'cycle2_mined','cycle2_mined','보험업감독규정 (금융위원회 고시, 국가법령정보센터) / 보험업감독업무시행세칙 별표15 (생명보험 표준약관, 금감원)','ai_draft','high','admin'),
('term','재가입 심사','기존 보험계약이 만기·해지·실효된 후 동일 또는 유사 상품에 새롭게 청약하는 경우 수행하는 인수심사. 계약전환과 달리 재가입 시에는 새로운 청약으로 보아 현재의 건강 상태·직업 등에 대한 고지의무가 다시 발생하며(상법 제651조), 보험회사는 재심사를 통해 표준 인수 또는 조건부 인수 여부를 결정한다.','인수',array['재가입','재청약','고지의무재발생','인수심사','만기재가입'],'cycle2_mined','cycle2_mined','상법 제651조 (국가법령정보센터) / 생명보험 표준약관 (보험업감독업무시행세칙 별표15, 금감원)','ai_draft','high','admin'),
('term','비흡연자 할인','흡연 여부가 생명보험의 주요 사망·질병 위험 요인임을 반영해, 일정 기간 이상 비흡연 상태인 피보험자에게 보험료를 할인 적용하는 제도. 우량체(건강체) 할인의 구성 요소 중 하나이며, 금연 요건 기간(통상 1년 또는 2년 이상)과 검증 방법(소변·혈액 검사 등)은 보험회사마다 다르고 할인율도 각사 공시 기준에 따라 상이하다.','인수',array['비흡연자할인','금연할인','우량체','건강체할인','생명보험보험료'],'cycle2_mined','cycle2_mined','보험개발원 민영건강보험 언더라이팅 선진화 방안 (연구보고서 2003-1, kiri.or.kr) / 각사 우량체 할인 공시','ai_draft','medium','admin'),
('term','인수심사 스코어링','보험 청약자의 위험 요소(나이·성별·직업·건강·병력 등)를 수치화하여 위험 점수를 산출하고 인수 가능 여부와 조건을 판정하는 언더라이팅 기법. AI·머신러닝 기술을 적용한 자동심사 시스템으로 발전하고 있으며, 점수 기준에 따라 표준 인수·조건부 인수·거절 등을 결정한다. 국내에서는 보험회사 자체 시스템 및 관련 연구가 진행되고 있으나, 구체적 기준은 각사 내규 소관이다.','인수',array['인수심사스코어링','자동심사','언더라이팅시스템','위험점수','AI심사'],'cycle2_mined','cycle2_mined','보험사 언더라이팅 기준 설정을 위한 스코어링 기법 연구 (KCI, ART001353137) / 보험개발원 연구보고서','ai_draft','medium','admin'),
('term','중복·과다 보험가입 방지 가이드라인','보험사기 목적의 고액 보험금 취득을 예방하기 위해 생명보험협회·손해보험협회가 2023년 9월 1일 제정한 인수심사 지침. 사망담보 가입금액과 기대소득 비교, 납입보험료와 소득 비교 등 강화된 재정심사를 고위험 청약에 적용하며, 인수기준 초과 승인 시 사유·근거자료 보존 및 보상·보험사기조사 부서 공유 등 사후관리 절차를 포함한다. 각 보험회사는 내규에 반영하여 자율 운영한다.','인수',array['중복보험방지','과다보험방지','인수심사가이드라인','재정심사','생손보협회'],'cycle2_mined','cycle2_mined','중복·과다 보험가입 방지 인수심사 가이드라인 (생명보험협회·손해보험협회, 2023.9.1. 제정) / 보험연구원 KIRI 보험법 리뷰 (kiri.or.kr)','ai_draft','high','admin'),
('term','인수등급','보험회사가 피보험자의 건강·직업·취미 등을 종합적으로 심사한 후 위험 수준에 따라 분류하는 등급 체계. 통상 표준체(일반 인수)·우량체(할인 인수)·표준미달체(조건부 인수 — 할증·감액·부담보 등)·거절체(인수 불가)로 구분된다. 각 등급별로 적용 보험료와 계약 조건이 다르다.','인수',array['인수등급','표준체','표준미달체','거절체','우량체','언더라이팅'],'cycle2_mined','cycle2_mined','보험개발원 민영건강보험 언더라이팅 선진화 방안 (연구보고서 2003-1, kiri.or.kr) / 생명보험협회 자격시험 자료','ai_draft','high','admin'),
('term','부담보 해제','조건부 인수 시 설정된 부담보 조건이 해제되어 해당 부위·질병이 보장에 포함되는 상태로 전환되는 것. 표준약관상 부담보 기간(한시 부담보)의 경우 청약일로부터 5년 이내에 해당 부위·질병으로 추가 진단·치료(단순 건강검진 제외)가 없으면 5년 경과 후 보장이 개시된다. 전기간 부담보의 경우 기간 경과만으로 자동 해제되지 않으며, 분쟁 시 금감원 분쟁조정 신청이 가능하다.','인수',array['부담보해제','한시부담보','전기간부담보','5년경과','보장복원','조건부계약해제'],'cycle2_mined','cycle2_mined','특정 신체부위·질병 보장제한부 인수제도 특별약관 (원수사 공시 약관) / 금감원 분쟁조정 지침 (금융감독원 fss.or.kr) / 한국금융신문 2014.4.20. (금감원 지침 관련)','ai_draft','medium','admin'),
('term','신체부위 부담보','특정 신체 부위(허리·어깨·무릎·위·대장 등)에서 발생하는 질병 또는 상해에 대한 보험금 지급을 제외하는 조건. 해당 부위의 기존 병력이나 위험 상태가 확인될 때 설정하며, 특정 질병 부담보와 함께 신체부위·질병 합산 최대 4개까지만 설정이 가능하고 그 이상이 필요할 경우 청약이 거절될 수 있다. 특정 질병 부담보와 구별된다.','인수',array['신체부위부담보','부담보','특정부위제외','조건부인수','인수심사'],'cycle2_mined','cycle2_mined','특정 신체부위·질병 보장제한부 인수제도 특별약관 (원수사 공시 약관) / 생명보험 표준약관 (보험업감독업무시행세칙 별표15, 금감원)','ai_draft','medium','admin'),
('term','특정질병 부담보','암·척추질환·심장질환 등 특정 질병을 보장 범위에서 제외하는 조건부 인수 방식. 해당 질병의 기존 병력이 있거나 위험 수준이 높을 때 설정되며, 신체부위 부담보와 합산하여 통상 4개까지 설정이 가능하고 그 이상이 필요한 경우 청약이 거절될 수 있다. 한시 부담보(일정 기간 후 해제 가능) 또는 전기간 부담보(계약 전 기간 적용)로 구분되어 적용된다.','인수',array['특정질병부담보','질병부담보','조건부인수','부담보','언더라이팅'],'cycle2_mined','cycle2_mined','특정 신체부위·질병 보장제한부 인수제도 특별약관 (원수사 공시 약관) / 생명보험 표준약관 (보험업감독업무시행세칙 별표15, 금감원)','ai_draft','high','admin'),
('term','주관적 위험(언더라이팅)','피보험자 개인의 성격, 생활 습관, 가치관, 재정적 압박 등 내적·심리적 요인에 기인하는 위험. 객관적으로 측정하기 어려워 언더라이터의 판단에 의존하는 경우가 많다. 보험학에서는 물리적 위험(physical hazard)과 대비되는 개념으로, 도덕적 위험(moral hazard)·심리적 위험(morale hazard)이 주관적 위험의 대표적 유형이다. 적부조사·재정심사를 통해 보완적으로 확인하며, 보험개발원 연구보고서에서 언더라이팅 위험 평가 요소로 분류된다.','인수',array['주관적위험','도덕적위험','심리적위험','위험평가','언더라이팅','인수심사'],'cycle2_mined','cycle2_mined','보험개발원 민영건강보험 언더라이팅 선진화 방안 (연구보고서 2003-1, kiri.or.kr) / 보험연구원 보험위험과 상품설계 자료 (nre2018-06, kiri.or.kr)','ai_draft','medium','admin'),
('term','보험계약 인수결과 통보','보험회사가 청약을 검토한 후 계약자에게 표준 승낙, 조건부 승낙(할증·감액·부담보 등), 인수 거절 중 하나의 결과를 서면 또는 전자적 방법으로 알리는 절차. 생명보험 표준약관(보험업감독업무시행세칙 별표15 제16조 제2항)상 보험회사는 청약일로부터 30일 이내에 승낙 여부를 통보해야 하며, 이 기간을 초과하면 승낙한 것으로 본다. 다만 피보험자가 신체검사를 받아야 하는 경우에는 그 기간을 신체검사를 받은 날부터 기산한다.','인수',array['인수결과통보','승낙','조건부승낙','인수거절','30일규정','신체검사기산'],'cycle2_mined','cycle2_mined','생명보험 표준약관 제16조 제2항 (보험업감독업무시행세칙 별표15, 금감원) / 찾기쉬운 생활법령정보 (easylaw.go.kr)','ai_draft','high','admin'),
('term','고지의무 위반 효과','계약자 또는 피보험자가 청약 시 중요한 사항을 고의 또는 중대한 과실로 사실과 다르게 알린 경우 보험회사가 계약을 해지하고 보험금을 지급하지 않을 수 있는 권리. 상법 제651조에 따라 보험회사는 고지의무 위반 사실을 안 날로부터 1개월, 계약을 체결한 날로부터 3년 이내에만 해지권을 행사할 수 있다. 이 기간이 경과하면 해지권이 소멸한다.','계약',array['고지의무위반','계약해지','상법651조','해지권소멸','보험금지급거절','제척기간'],'cycle2_mined','cycle2_mined','상법 제651조 (국가법령정보센터) / 생명보험 표준약관 (보험업감독업무시행세칙 별표15)','ai_draft','high','admin'),
('term','보험사기(보험범죄)','보험금을 부정하게 취득할 목적으로 보험사고의 발생·원인·내용을 조작하거나 허위 청구를 하는 행위. 고의 사고 유발, 사고 과장, 허위 입원·수술, 타인을 이용한 보험 편취 등이 포함된다. 보험사기방지 특별법 제8조에 따라 10년 이하의 징역 또는 5천만 원 이하의 벌금에 처한다. 보험사기이득액이 5억 원 이상인 경우에는 가중처벌된다. 금융감독원 보험사기신고센터(보험사기방지법상 신고채널)에 신고할 수 있다.','민원',array['보험사기','보험범죄','보험사기방지법','허위청구','금감원신고','가중처벌'],'cycle2_mined','cycle2_mined','보험사기방지 특별법 제8조 (국가법령정보센터, 2024.8.14. 시행) / 금융감독원 보험사기신고센터 (fss.or.kr)','ai_draft','high','admin'),
('term','언더라이터','보험 청약서 및 관련 서류를 검토하여 보험 인수 여부와 조건을 결정하는 보험회사의 전문 심사 인력. 피보험자의 건강, 직업, 재정 상태, 취미 등 위험 요소를 종합 평가하고 표준 인수·조건부 인수·거절 여부를 판정한다. 생명보험협회 자격시험센터(exam.insure.or.kr)에서 ''생명보험언더라이터'' 자격시험을 운영하며, 이는 자격기본법에 따라 등록된 민간자격(국가공인자격 아님)이다.','인수',array['언더라이터','인수심사자','위험심사','보험심사','생명보험협회자격','민간자격'],'cycle2_mined','cycle2_mined','생명보험협회 자격시험센터 (exam.insure.or.kr) / 보험개발원 언더라이팅 연구자료','ai_draft','medium','admin'),
('term','자동인수한도','특약재보험에서 재보험자가 사전 별도 협의 없이 자동으로 인수를 보장하는 원보험 계약의 최고 책임금액 한도. 이 한도를 초과하는 대형 계약은 임의재보험(Facultative Reinsurance)으로 별도 협의가 필요하다. 보험업감독규정 관련 재보험관리기준에 따라 각 보험회사는 자동인수한도를 포함한 재보험 관리 기준을 내부 규정으로 수립해야 한다.','계약',array['자동인수한도','재보험','특약재보험','인수한도','재보험관리','임의재보험'],'cycle2_mined','cycle2_mined','보험업감독규정 및 시행세칙 재보험관리기준 (국가법령정보센터) / 보험연구원 재보험 연구보고서','ai_draft','medium','admin'),
('term','4세대 실손의료보험','2021년 7월 1일부터 판매된 표준화 실손의료보험으로, 급여 실손의료비를 보장하는 기본형과 비급여 실손의료비를 보장하는 특별약관(비급여 일반·3대비급여)으로 분리 구성된다. 급여 자기부담률 20%, 비급여 자기부담률 30%를 적용하며, 비급여 특약에 보험료 할인·할증 제도(2024년 7월 1일 시행)가 연동된다. 이전 1~3세대 실손의 구조적 도덕적 해이 개선을 목적으로 설계됐다.','보장',array['실손보험','4세대','급여비급여분리','표준화','2021'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험(4세대) (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','급여·비급여 분리 구조','4세대 실손의료보험에서 급여(국민건강보험 요양급여 본인부담분)와 비급여(건강보험 적용 제외 의료비)를 별도 담보로 분리하여 각기 다른 보험료·자기부담률·할인할증을 적용하는 설계 방식이다. 기본형은 급여의료비만, 특별약관은 비급여(일반·3대비급여)만 보장하며, 특약은 기본형과 함께만 가입 가능하다.','보장',array['급여분리','비급여분리','실손구조','4세대','특약'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험 안내 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','비급여 보험료 차등제(할인·할증)','4세대 실손의료보험 비급여 특약 가입자를 대상으로, 직전 1년간 비급여 보험금 수령액에 따라 갱신 시 보험료를 차등 적용하는 제도(2024년 7월 1일 시행). 비급여 보험금 미수령자는 할인(약 62.1% 대상), 100만 원 이상 수령자는 할증(+100~300%, 약 1.3% 대상)이 적용된다. 산정특례대상질환 의료비 및 장기요양등급 1·2등급자 의료비는 산정에서 제외된다. 할인·할증 등급은 갱신 후 1년간만 유지되며, 1년 후 재산정된다.','보장',array['비급여할인할증','보험료차등','실손갱신','4세대','2024'],'cycle2_mined','cycle2_mined','금융감독원 보도자료 — 비급여 의료이용량 연계 보험료 차등제 시행 안내 (fss.or.kr) / 손해보험협회 소비자 공시포털 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','3대비급여 특약','4세대 실손의료보험에서 도수·체외충격파·증식치료(연 350만 원·50회 한도), 비급여 주사료(연 250만 원·50회 한도), 비급여 자기공명영상진단(MRI/MRA, 연 300만 원 한도)을 각각 보장하는 특별약관 3종을 통칭한다. 각 특약별로 자기부담률 30%가 적용되며, 비급여 보험료 차등제(할인·할증) 적용 대상에 포함된다.','보장',array['3대비급여','도수치료','비급여주사','MRIMRA','실손특약'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험(4세대) 보장내용 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','도수치료','자격을 갖춘 의료인이 시술자의 신체를 직접 활용하여 근골격계 질환 및 증상을 개선하는 의료행위로, 국민건강보험 비급여 항목에 해당한다. 4세대 실손 3대비급여 특약의 보장 대상이며, 처음 10회는 보장하고 이후 객관적으로 인정되는 검사 결과 등으로 증상 개선이 확인된 경우에 한하여 10회 단위로 연간 50회(350만 원 한도)까지 보상한다. 자기부담률 30% 적용.','보장',array['도수치료','비급여','근골격계','3대비급여','실손'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험(4세대) 표준약관 (kpub.knia.or.kr)','ai_draft','medium','admin'),
('term','체외충격파치료','체외에서 충격파를 병변에 가해 손상 조직의 재생을 촉진하거나 통증을 완화하는 비급여 의료행위(체외충격파쇄석술은 제외). 도수·체외충격파·증식치료를 묶은 4세대 실손 3대비급여 특약의 보장 대상으로, 연간 350만 원·50회 한도 내에서 자기부담률 30%를 공제한 금액을 보상한다.','보장',array['체외충격파','비급여','근골격계','3대비급여','실손'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험(4세대) 표준약관 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','증식치료','인대·건(힘줄)·관절·연골 등에 증식 물질(고농도 포도당 등)을 주사하여 조직 재생을 촉진하는 비급여 의료행위(프롤로치료라고도 함). 4세대 실손 3대비급여 특약에서 도수·체외충격파 치료와 함께 합산하여 연 350만 원·50회 한도로 보장되며, 자기부담률 30%를 차감한 금액을 지급한다.','보장',array['증식치료','프롤로치료','비급여','3대비급여','실손'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험(4세대) 표준약관 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','비급여 MRI·MRA 특약','4세대 실손의료보험 3대비급여 특약 중 하나로, 국민건강보험 비급여로 분류된 자기공명영상진단(MRI) 및 자기공명혈관조영술(MRA) 비용을 연간 300만 원 한도, 자기부담률 30% 공제 후 보상한다. 건강보험 급여로 전환된 MRI 항목은 기본형 급여 담보로 청구해야 한다.','보장',array['MRI','MRA','비급여특약','3대비급여','실손'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험(4세대) 보장내용 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','실손의료보험 재가입주기','실손의료보험 계약의 보험기간이 만료될 때 가입자가 자동으로 재가입할 수 있는 기간 주기. 4세대 실손은 5년 재가입형 구조로 운영되며, 재가입 시 연령·위험률 변동을 반영한 보험료가 재산출된다. 재가입 거절 사유는 제한적이며, 재가입 시 고지의무 적용 여부는 일부 예외적 심사 항목(예: 직전 1년간 정신질환 치료 이력 등)에 한정되므로 전면적인 신규 고지의무 적용으로 일반화하기 어렵다. 구체적 적용 범위는 금감원 표준사업방법서 및 개별 약관에서 확인해야 한다.','계약',array['재가입주기','5년갱신','실손갱신형','보험기간'],'cycle2_mined','cycle2_mined','보험업감독규정 (국가법령정보센터 — law.go.kr) / 손해보험협회 소비자 공시포털 (kpub.knia.or.kr)','ai_draft','medium','admin'),
('term','통원 한도·횟수 제한','4세대 실손의료보험에서 외래진료 및 처방조제비 통원 의료비는 1회당 20만 원 한도로 보상하며, 비급여 특약 통원은 연간 100회를 초과할 수 없다. 1회 통원에서 외래와 처방조제비가 함께 발생하면 합산하여 한도를 적용한다. 자기부담금은 급여의 경우 의료기관 종별에 따라 1만 원~2만 원 또는 보장대상 의료비의 20% 중 큰 금액으로 공제하고, 비급여의 경우 3만 원 또는 보장대상 의료비의 30% 중 큰 금액으로 공제한다.','보장',array['통원한도','연간횟수','외래한도','실손','1회한도'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험(4세대) 보장내용 (kpub.knia.or.kr) / 금융위원회 보도자료','ai_draft','medium','admin'),
('term','본인부담상한제','국민건강보험법에 따라 연간(1월 1일~12월 31일) 가입자가 부담한 급여 본인일부부담금 총액이 소득 분위별 상한액을 초과할 경우 초과분을 건강보험공단이 환급하는 제도(국민건강보험법 제44조, 동법 시행령 제19조). 비급여·선별급여·전액본인부담금 등은 상한 산정에서 제외되며, 2024년 사전급여 최고상한액은 808만 원이다.','보장',array['본인부담상한제','건강보험환급','상한액','국민건강보험'],'cycle2_mined','cycle2_mined','국민건강보험공단 — 2024년도 본인부담상한액 안내 (nhis.or.kr) / 국민건강보험법 시행령 제19조','ai_draft','high','admin'),
('term','산정특례제도','암·심장·뇌혈관·희귀질환·중증난치·중증화상 등 고액 장기 치료가 필요한 중증 질환자를 대상으로 국민건강보험 급여 본인부담률을 경감하는 제도(국민건강보험법 제44조, 동법 시행령 제19조 별표2 기반 고시). 암·중증화상은 본인부담률 5%, 희귀질환·중증난치질환·중증치매는 10%, 결핵 및 잠복결핵감염은 본인부담 면제된다. 4세대 실손 할인·할증 산정 시 산정특례 질환으로 인한 의료비는 할증 대상에서 제외된다.','보장',array['산정특례','중증질환','본인부담경감','건강보험','희귀난치'],'cycle2_mined','cycle2_mined','국민건강보험공단 — 본인일부부담금 산정특례 제도 안내 (nhis.or.kr) / 국민건강보험법 시행령 별표2','ai_draft','high','admin'),
('term','선별급여','치료 효과의 불확실성 등을 이유로 건강보험 급여 적용 여부가 불분명한 의료행위에 대해, 비용 효과성 등을 조건으로 급여를 인정하되 본인부담률을 일반 급여(5~20%)보다 높게(30~90%) 적용하는 국민건강보험 제도(국민건강보험법 제41조의4, 동법 시행령 제18조의4). 실손보험에서 선별급여 본인부담분은 급여 담보의 보상 대상에 포함된다.','보장',array['선별급여','본인부담률','건강보험','실손청구'],'cycle2_mined','cycle2_mined','국민건강보험 요양급여의 기준에 관한 규칙 (국가법령정보센터 — law.go.kr) / 선별급여 지정 및 실시 등에 관한 기준 (nhis.or.kr)','ai_draft','high','admin'),
('term','잔존물대위','손해보험에서 보험자가 보험금을 전액 지급한 후 보험 목적물에 대한 피보험자의 권리를 법률상 당연히 취득하는 제도(상법 제681조). 전부 멸실 시에만 적용되며, 보험자는 취득한 잔존물 처분으로 수익을 얻을 수 있다. 일부 손해의 경우에는 잔존물대위가 인정되지 않는다.','보장',array['잔존물대위','보험자대위','상법제681조','손해보험'],'cycle2_mined','cycle2_mined','상법 제681조 (국가법령정보센터 — law.go.kr)','ai_draft','high','admin'),
('term','청구권대위','손해가 제3자의 행위로 발생한 경우 보험자가 보험금을 지급한 범위에서 피보험자의 제3자에 대한 손해배상청구권을 취득하는 제도(상법 제682조). 보험자는 지급 보험금 한도 내에서 제3자에 대한 구상권을 행사할 수 있으며, 피보험자의 남은 손해청구권을 침해하지 않는 범위에서 행사해야 한다.','보장',array['청구권대위','보험자대위','상법제682조','구상권','손해보험'],'cycle2_mined','cycle2_mined','상법 제682조 (국가법령정보센터 — law.go.kr)','ai_draft','high','admin'),
('term','손해방지의무','보험사고 발생 후 보험계약자·피보험자가 손해의 발생 방지 및 확대 경감을 위해 노력해야 할 법률상 의무(상법 제680조). 위반 시 보험자는 해당 부분의 손해 보상을 거절할 수 있다. 손해방지를 위해 지출된 필요·유익한 비용은 보험금액을 초과하더라도 보험자가 부담한다.','계약',array['손해방지의무','상법제680조','손해방지비용','보험계약자의무'],'cycle2_mined','cycle2_mined','상법 제680조 (국가법령정보센터 — law.go.kr)','ai_draft','high','admin'),
('term','일부보험 비례보상','보험가액의 일부에만 보험을 가입한 경우(보험금액 < 보험가액) 손해액에 대해 보험금액의 보험가액에 대한 비율로만 보상하는 원칙(상법 제674조). 예를 들어 보험가액 1억 원에 보험금액이 8,000만 원인 경우 손해액의 80%만 보상된다. 당사자 간 별도 약정이 있으면 보험금액 한도 내 실손 보상도 가능하다.','보장',array['일부보험','비례보상','상법제674조','부보율','손해보험'],'cycle2_mined','cycle2_mined','상법 제674조 / 찾기쉬운 생활법령 — 손해보험의 개관 (easylaw.go.kr)','ai_draft','high','admin'),
('term','중복보험 비례보상 조정','동일 보험 목적에 대해 여러 보험사와 계약한 중복보험에서 보험금액 합계가 보험가액을 초과하는 경우, 각 보험사는 자신의 보험금액 한도에서 연대책임을 지며, 각자의 보험금액 비율에 따라 책임을 분담한다(상법 제672조). 보험가액을 초과하는 보험금은 지급하지 않는다. 실손의료보험의 경우 다수 계약이 있어도 실제 의료비 한도 내에서만 지급하며 비례 분담한다.','보장',array['중복보험','비례보상조정','상법제672조','실손중복','연대책임'],'cycle2_mined','cycle2_mined','상법 제672조 (국가법령정보센터 — law.go.kr)','ai_draft','high','admin'),
('term','기평가보험(협정보험가액)','계약 체결 시 당사자가 미리 보험가액을 협정(약정)한 손해보험으로, 사고 발생 시 그 협정가액을 보험가액으로 추정한다(상법 제670조). 협정가액이 실제 사고 발생 시의 가액을 현저히 초과하는 경우에는 사고 발생 시의 가액을 보험가액으로 한다. 선박보험 등에서 주로 활용되며, 사후 가액 분쟁을 방지하는 기능을 한다.','계약',array['기평가보험','협정보험가액','상법제670조','손해보험가액'],'cycle2_mined','cycle2_mined','상법 제670조 / 찾기쉬운 생활법령 — 손해보험의 개관 (easylaw.go.kr)','ai_draft','high','admin'),
('term','고지의무 위반과 인과관계','고지의무 위반으로 보험자가 계약을 해지하더라도, 위반 사실과 보험사고 발생 사이에 인과관계가 없음이 증명된 경우 보험자는 보험금을 지급할 책임을 진다(상법 제655조 단서). 인과관계 부존재에 대한 입증책임은 보험계약자 측이 부담한다.','계약',array['고지의무위반','인과관계','상법제655조','보험금지급','계약해지'],'cycle2_mined','cycle2_mined','상법 제655조 (국가법령정보센터 — law.go.kr) / 국가법령정보센터 판례(보험금 관련 대법원 판결)','ai_draft','high','admin'),
('term','기왕증 기여도 감액','보험사고 이전에 존재하던 신체장해나 질병이 보험사고로 인한 손해 확대에 기여한 경우, 그 기여도를 산정하여 보험금에서 감액 지급하는 보험 실무 기준. 약관 또는 대법원 판례에 근거하며, 기왕증 기여도 감액이 인정되려면 기왕증과 사고 손해 확대 사이의 인과관계가 입증되어야 한다. 기여도 산정 방식이나 감액률은 개별 사안마다 달라 분쟁 대상이 될 수 있으며, 일방적 감액은 금감원 민원·소송 대상이 된다.','보장',array['기왕증','기여도감액','보험금산정','손해사정','인과관계'],'cycle2_mined','cycle2_mined','국가법령정보센터 판례 — 보험금 기왕증 기여도 관련 대법원 판결 (law.go.kr)','ai_draft','medium','admin'),
('term','계약전환제도(실손의료보험)','기존 1~3세대 실손의료보험 가입자가 가입 회사의 4세대 실손의료보험으로 계약을 변경할 수 있는 제도. 별도 심사 없이 전환 가능하며, 전환 후 6개월 이내에 보험금을 수령하지 않은 경우 철회하고 구계약으로 복귀할 수 있다(전환 후 3개월 이내에는 보험금 수령 여부와 무관하게 철회 가능). 4세대 전환 시 전환 전 무사고 기간도 무사고할인(직전 2년 무사고 시 비급여 보험료의 10% 할인)에 합산 인정된다.','계약',array['계약전환','실손전환','4세대전환','구계약신계약','철회'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손 전환제도 관련 안내 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','실손보험 무사고할인','4세대 실손의료보험에서 비급여 특약 직전 2년간 보험금을 수령하지 않은 경우 갱신 시 비급여 보험료의 10%를 할인하는 제도. 4세대로 계약전환 시 전환 전 계약의 무사고 기간도 합산 인정된다. 비급여 차등제에 따른 할인(보험금 미수령자 약 5%)과 중복 적용이 가능하다.','보장',array['무사고할인','실손갱신','비급여할인','4세대실손','보험료할인'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손 전환제도 안내 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','유병자(간편심사) 실손의료보험','치료이력이 있거나 경증 만성질환(고혈압·당뇨 등)을 보유한 유병력자를 대상으로 가입 심사 항목(총 6개, 병력·치료이력 관련 3개)을 완화하여 판매하는 실손의료보험. 투약 여부는 심사에서 제외되며, 치료가 완료되었거나 투약만으로 관리 중인 경증 만성질환자도 가입 가능하다. 보장 범위는 일반 실손의료보험 기본형과 동일하나 처방조제 비용은 보장되지 않으며 자기부담금이 더 높다.','인수',array['유병자실손','간편심사','만성질환','고혈압당뇨','가입심사완화'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 유병력자 실손의료보험 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','실손보험 청구간소화(전산청구)','의료기관이 직접 전산 시스템을 통해 실손보험 보험금 청구 서류를 보험사에 제출하도록 하여 가입자의 번거로움을 줄이는 제도. 보험업법 제102조의7 개정에 따라 병원급 이상은 2024년 10월 25일, 의원급 및 약국은 2025년 10월 25일부터 시행된다.','민원',array['청구간소화','전산청구','보험업법제102조의7','실손청구편의'],'cycle2_mined','cycle2_mined','보험업법 제102조의7 / 보험업법 시행령 제48조의2 (국가법령정보센터 — law.go.kr) / 대한민국 정책브리핑 (korea.kr)','ai_draft','high','admin'),
('term','비급여 진료비 고지의무','의료기관 개설자는 비급여 대상 항목과 가격을 환자나 보호자가 쉽게 알 수 있도록 고지해야 할 의무를 부담한다(의료법 제45조). 보건복지부 행정규칙인 ''비급여 진료비용 등의 고지 지침''에 따라 사전 설명이 의무화된 항목이 정해져 있으며, 위반 시 행정처분이 가능하다.','민원',array['비급여고지','의료법제45조','비급여진료비','사전설명의무'],'cycle2_mined','cycle2_mined','의료법 제45조 / 비급여 진료비용 등의 고지 지침 (국가법령정보센터 — law.go.kr)','ai_draft','high','admin'),
('term','손해보험 손해율','경과보험료 대비 발생손해액의 비율로, 보험료 수입 중 실제 보험금으로 지급된 비율을 나타내는 지표. 실손의료보험에서는 손해율이 높을수록 갱신 시 보험료 인상 요인이 되며, 손해보험협회는 매년 세대별·담보별 경과손해율을 공시한다. 손해율 100% 초과 시 보험료 인상이 불가피하다.','판매',array['손해율','경과손해율','실손공시','갱신보험료','보험수지'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 보험료 인상률 및 손해율 공시 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','실손보험 세대별 분류(1~4세대)','실손의료보험은 판매 시점에 따라 1세대(2009년 10월 이전), 2세대 선택형Ⅰ(2009.10~2015.8)·표준형(2013.1~2017.3)·선택형Ⅱ(2015.9~2017.3), 3세대 표준형·선택형(2017.4~2021.6), 4세대 표준화(2021.7~)로 구분된다. 세대별로 자기부담률·보장 구조·갱신 주기·비급여 처리 방식이 상이하며, 4세대가 현재 판매 기준이다.','계약',array['실손세대구분','1세대2세대3세대4세대','실손표준화','2009표준화'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험 안내 및 전환제도 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','보험금청구권 소멸시효','보험금청구권은 3년간 행사하지 않으면 시효의 완성으로 소멸한다(상법 제662조, 2014년 개정으로 2년에서 3년으로 연장). 소멸시효의 기산점은 상법 제662조에 별도 규정이 없으므로 민법 제166조 제1항에 따라 ''권리를 행사할 수 있는 때'', 즉 원칙적으로 보험사고 발생일부터 진행한다. 다만 보험사고 발생을 객관적으로 알 수 없는 사정이 있는 경우(예: 진단 확정이 필요한 질병 등) 판례는 ''객관적 인식가능성''을 기준으로 기산점을 완화한다. ''영수증 발행일이 아닌 진료일 기준으로 시효가 기산된다''는 표현은 공식 법령이나 대법원 확립 판례로 뒷받침되지 않으므로 단정을 피하고 ''보험사고 발생일(진료일)이 원칙적 기산점이나 개별 사안에 따라 달라질 수 있다''로 표현하는 것이 적절하다.','민원',array['소멸시효','보험금청구권','상법제662조','3년시효','청구기한','기산점'],'cycle2_mined','cycle2_mined','상법 제662조 (국가법령정보센터 — law.go.kr); 민법 제166조 제1항','ai_draft','medium','admin'),
('term','보험약관 교부·설명의무','보험자는 계약 체결 시 보험계약자에게 약관을 교부하고 보험상품 내용·보험료율·면책사유 등 중요 사항을 구체적으로 설명해야 한다(상법 제638조의3 제1항). 의무 위반 시 계약자는 계약 성립일로부터 1개월 이내에 계약을 취소할 수 있으며(동조 제2항), 보험자는 이미 납입된 보험료에 이자를 더해 반환해야 한다.','판매',array['약관교부','설명의무','상법제638조의3','중요사항설명','계약취소','1개월취소'],'cycle2_mined','cycle2_mined','상법 제638조의3 제1항·제2항 (국가법령정보센터 — law.go.kr)','ai_draft','high','admin'),
('term','실손보험 갱신보험료 산출 원칙','실손의료보험의 갱신 보험료는 보험나이 증가, 위험률 변동(손해율 기반), 의료수가 변동을 반영하여 재산출한다. 가입 시점에 정확한 요율 산정이 어려운 특성상 갱신형으로 운용되며, 갱신 시 가입자의 건강상태는 재심사하지 않는다. 보험업감독규정 제7-63조 제2항에 따라 위험구분 단위별 보험료 변경은 매년 ±25%를 초과할 수 없다. 갱신보험료 인상률 및 손해율은 손해보험협회 소비자 공시포털에 세대별·담보별로 매년 공시된다.','계약',array['갱신보험료','위험률변동','의료수가','보험나이','실손갱신','인상률상한'],'cycle2_mined','cycle2_mined','보험업감독규정 제7-63조 제2항; 손해보험협회 소비자 공시포털 (kpub.knia.or.kr)','ai_draft','medium','admin'),
('term','요양급여 본인일부부담금','국민건강보험 가입자가 요양급여를 받을 때 의료비의 일부를 직접 부담하는 금액(국민건강보험법 제44조, 시행령 제19조 별표2). 의료기관 종별(상급종합·종합병원·의원·약국 등)과 입원·외래 여부에 따라 부담률이 차등 적용된다. 실손의료보험에서 이 본인부담금이 급여 담보의 보상 대상이 된다.','보장',array['본인일부부담금','요양급여','국민건강보험','실손청구대상','종별부담률'],'cycle2_mined','cycle2_mined','국민건강보험법 제44조·시행령 제19조 별표2 (국가법령정보센터 — law.go.kr); 국민건강보험공단 (nhis.or.kr)','ai_draft','high','admin'),
('term','대위변제와 구상권','손해보험에서 보험자가 보험금을 지급한 후 제3자(가해자)에게 대위하여 행사하는 청구권을 보험자대위(상법 제682조)라 한다. 보험자대위는 보험자가 피보험자의 제3자에 대한 청구권을 지급 한도 내에서 법률상 당연히 취득하는 것이다. 한편, ''대위변제''는 채무를 변제할 이익이 있는 자가 대신 변제하고 원 채권자의 권리를 취득하는 ''변제자대위''(민법 제481조)를 뜻하며, 보험자대위와는 법적 근거와 성질이 다른 별개의 권리다. 구상권은 타인의 채무를 변제한 자가 채무자에 대해 갖는 상환청구권으로, 변제자대위권과도 구별된다.','보장',array['대위변제','구상권','보험자대위','상법제682조','제3자','변제자대위'],'cycle2_mined','cycle2_mined','상법 제682조 (국가법령정보센터 — law.go.kr); 민법 제481조; 대법원 판례 (scourt.go.kr)','ai_draft','high','admin'),
('term','비급여 의료비 보고·공개 제도','의료기관은 비급여 진료비용의 항목·기준·금액·진료내역 등을 보건복지부에 주기적으로 보고해야 하고, 정부는 이를 공개할 수 있다(의료법 제45조의2, 「비급여 진료비용 등의 보고 및 공개에 관한 기준」 보건복지부 고시). 2024년부터 모든 의원급 이상 의료기관으로 보고 의무가 확대됐다. 이는 비급여 의료비의 적정성 관리와 환자 알권리 보장을 위한 것으로, 실손보험사의 비급여 관리와도 연계된다.','민원',array['비급여공개','의료비보고','의료법제45조의2','비급여적정성','비급여보고제도'],'cycle2_mined','cycle2_mined','의료법 제45조의2 (국가법령정보센터 — law.go.kr); 보건복지부 고시 「비급여 진료비용 등의 보고 및 공개에 관한 기준」 (mohw.go.kr)','ai_draft','high','admin'),
('term','실손보험 손해율 연동 보험료 조정','실손의료보험 갱신 시 직전 경과손해율을 기초로 보험료를 조정하는 체계. 보험업감독규정 제7-63조 제2항에 따라 위험구분 단위별 보험료 변경은 매년 ±25%를 초과하지 않도록 제한된다. 원본에 기재된 ''110~130% 초과 시 인상''이라는 특정 기준치는 공식 감독규정에서 명문으로 확인되지 않으므로 단정을 피해야 한다. 보험료 인상률 및 손해율은 손해보험협회 공시시스템에 세대별·담보별로 매년 공시된다.','계약',array['손해율연동','보험료조정','실손갱신인상','경과손해율공시','인상률상한'],'cycle2_mined','cycle2_mined','보험업감독규정 제7-63조 제2항; 손해보험협회 소비자 공시포털 (kpub.knia.or.kr)','ai_draft','medium','admin'),
('term','실손보험 입원 자기부담금','4세대 실손의료보험에서 입원 의료비 청구 시 피보험자가 부담하는 자기부담금은, 급여 입원의 경우 보장대상 의료비의 20%, 비급여 입원의 경우 30%다. 급여 입원에는 연간 본인부담 상한이 적용되나, 비급여 입원은 상한 없이 30% 전액 본인 부담이다. 자기부담률 상향(3세대 이전 대비)은 의료 남용 방지를 목적으로 한다.','보장',array['입원자기부담금','급여20퍼','비급여30퍼','실손','4세대','자기부담상한'],'cycle2_mined','cycle2_mined','손해보험협회 소비자 공시포털 — 실손의료보험(4세대) 보장내용 (kpub.knia.or.kr); 금융위원회 보도자료 (fsc.go.kr)','ai_draft','high','admin'),
('term','실손보험 다중 계약 비례보상 실무','동일 의료비에 대해 2개 이상의 실손의료보험 계약이 있는 경우, 상법 제672조(중복보험)에 따라 각 보험사는 자신의 보험금액 비율에 따라 실제 의료비 한도 내에서 비례 분담 지급한다. 피보험자가 양 사에 청구하더라도 합산 수령액은 실제 의료비를 초과할 수 없으며, 초과 수령 시 부당이득 반환 문제가 발생한다.','보장',array['다중계약','실손비례보상','중복청구','보험금한도','부당이득','상법제672조'],'cycle2_mined','cycle2_mined','상법 제672조 (국가법령정보센터 — law.go.kr); 손해보험협회 소비자포털 (consumer.knia.or.kr)','ai_draft','medium','admin'),
('term','보험 약관 취소권(1개월)','보험자가 약관 교부·설명의무(상법 제638조의3 제1항)를 위반한 경우, 보험계약자는 계약 성립일로부터 1개월 이내에 계약을 취소할 수 있다(동조 제2항). 취소된 경우 보험자는 납입된 보험료에 이자를 가산하여 반환해야 한다. 이는 불완전판매로 인한 소비자 보호 장치다. 참고로, 이 ''취소권(1개월)''은 보험업법상 ''청약철회권(보험증권 수령 후 15일, 청약일로부터 30일 이내)''과는 별개의 권리다.','민원',array['약관취소권','1개월취소','설명의무위반','불완전판매구제','상법제638조의3','청약철회구분'],'cycle2_mined','cycle2_mined','상법 제638조의3 제2항 (국가법령정보센터 — law.go.kr)','ai_draft','high','admin'),
('term','GI보험(일반질병보험)','일반질병(General Illness)을 보장 대상으로 하는 생명보험 상품으로, CI(중대질병)보험과 달리 엄격한 중증 요건 없이 해당 질병분류코드(KCD) 진단 확정만으로 보험금을 지급하는 것이 특징이다. CI보험은 중대한 암·뇌졸중·급성심근경색 등 엄격한 의학적 정의(침윤·파괴적 증상 등)를 충족해야 지급되는 반면, GI보험은 해당 질병 코드 진단으로 보험금이 지급된다. 다만 GI보험도 보장 범위는 상품별·약관별로 다를 수 있으며, 뇌경색 보장 여부 등은 약관을 직접 확인해야 한다. 생명보험협회는 CI·GI보험 상품 현황을 공시를 통해 관리한다.','보장',array['GI보험','일반질병','CI보험비교','질병진단비','생명보험','KCD코드'],'cycle2_mined','cycle2_mined','생명보험협회 공시 「CI·GI보험상품 현황」 (klia.or.kr); 보험저널 (insjournal.co.kr) — 업계 관행 설명','ai_draft','medium','admin'),
('term','중대한 암(Critical Cancer)','CI보험 약관상 보험금 지급 대상이 되는 악성 종양으로, 악성 종양세포가 존재하고 주위 조직으로 악성 종양세포의 침윤파괴적 증식으로 특징지을 수 있는 악성 종양을 말한다. 상피내암(행동양식 분류번호 /2, KCD D00~D09), 경계성 종양, 기타 비침습성 종양 등은 제외된다. 한국표준질병사인분류(KCD) 코드 C00~C97에 해당하는 악성 신생물이 대상이며, 전문의에 의한 조직 검사 결과 등 객관적 진단 확정이 필요하다.','보장',array['중대한 암','CI보험','악성종양','KCD','진단비','상피내암 제외'],'cycle2_mined','cycle2_mined','금융감독원 질병상해보험 표준약관 (fss.or.kr); 생명보험협회 보험약관상 질병분류 기준(KCD) 안내 (klia.or.kr); 통계청 한국표준질병사인분류(KCD) 8차 개정 (kostat.go.kr)','ai_draft','high','admin'),
('term','중대한 뇌졸중(Critical Stroke)','CI보험 약관에서 별도로 정의하는 중증 뇌혈관 질환으로, 뇌경색·뇌출혈 등으로 인해 영구적인 신경학적 결손(언어장애, 운동장애, 인지장애 등)이 남는 상태를 말한다. 일반 뇌졸중 진단비와 달리 일시적 허혈발작(TIA) 등 신경학적 결손이 남지 않는 경우는 지급 대상에서 제외되는 것이 일반적이다. KCD 뇌혈관 질환 코드(I60~I67)를 기반으로 한다. 단, CI보험 표준약관의 정확한 조문 내용은 상품·보험사별로 다를 수 있으므로 개별 약관 확인이 필요하다.','보장',array['중대한 뇌졸중','CI보험','뇌경색','뇌출혈','신경학적 결손','TIA'],'cycle2_mined','cycle2_mined','생명보험협회 뇌혈관질환 보장 주요 보험상품 현황 (klia.or.kr); 금융감독원 표준약관 (fss.or.kr)','ai_draft','medium','admin'),
('term','중대한 급성심근경색(Critical Acute Myocardial Infarction)','CI보험 약관에서 보험금 지급 요건으로 규정한 중증 심장질환으로, 관상동맥의 폐색으로 심근에 괴사가 발생한 질환 중 전형적인 임상증상과 심전도 변화, 심근효소 수치 이상을 모두 충족하는 경우를 말한다. 일반 급성심근경색 진단비(GI)보다 지급 요건이 엄격하며, KCD I21 코드에 해당한다.','보장',array['중대한 급성심근경색','CI보험','관상동맥','심근괴사','KCD I21','심근효소'],'cycle2_mined','cycle2_mined','생명보험협회 주요 CI·GI보험상품 현황 (klia.or.kr); 금융감독원 생명보험 표준약관 (fss.or.kr)','ai_draft','high','admin'),
('term','노인장기요양보험','고령이나 노인성 질병 등으로 6개월 이상 혼자서 일상생활을 수행하기 어려운 자에게 신체활동·가사활동 지원 또는 간병 등의 서비스를 제공하는 사회보험이다. 국민건강보험공단이 관리·운영하며 65세 이상 노인 또는 65세 미만이라도 치매·뇌혈관성질환 등 노인성 질병을 가진 자가 신청할 수 있다. 장기요양등급 판정 후 재가급여·시설급여·특별현금급여를 제공한다.','보장',array['노인장기요양보험','장기요양등급','재가급여','시설급여','간병'],'cycle2_mined','cycle2_mined','노인장기요양보험법 제1조·제2조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 노인장기요양보험 (easylaw.go.kr)','ai_draft','high','admin'),
('term','장기요양등급','노인장기요양보험 수급 자격을 구분하는 등급으로, 1~5등급 및 인지지원등급의 6단계로 구분된다. 1등급(95점 이상, 전적 도움 필요), 2등급(75점 이상~95점 미만), 3등급(60점 이상~75점 미만), 4등급(51점 이상~60점 미만), 5등급(45점 이상~51점 미만, 치매 환자 한정), 인지지원등급(45점 미만 치매 환자 한정)으로 구분된다. 90개 조사 항목 중 52개 항목 장기요양인정조사 결과를 점수화한 장기요양인정점수를 기준으로 등급판정위원회가 판정한다.','보장',array['장기요양등급','1등급','5등급','인지지원등급','장기요양인정점수'],'cycle2_mined','cycle2_mined','노인장기요양보험법 시행령 제7조 (국가법령정보센터 law.go.kr); 장기요양등급판정기준에 관한 고시 (law.go.kr)','ai_draft','high','admin'),
('term','인지지원등급','노인장기요양보험 등급 체계에서 장기요양인정점수가 45점 미만이더라도 치매(노인장기요양보험법 제2조에 따른 노인성 질병에 해당하는 치매로 한정) 진단을 받은 경우 부여되는 등급이다. 1~5등급에 해당하지 않는 경증 치매 환자를 지원하기 위해 신설된 등급으로, 주야간보호, 단기보호(가족휴가제), 종일 방문요양, 복지용구 등 일부 재가급여를 이용할 수 있다. 장기요양인정 유효기간은 2년이며, 인지지원등급 수급자는 시설급여를 이용할 수 없다.','보장',array['인지지원등급','치매','장기요양','경증치매','주야간보호'],'cycle2_mined','cycle2_mined','노인장기요양보험법 시행령 제7조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 노인장기요양보험 (easylaw.go.kr)','ai_draft','high','admin'),
('term','재가급여','노인장기요양보험에서 장기요양 수급자가 가정에서 생활하면서 이용하는 급여로, 방문요양·방문목욕·방문간호·주야간보호·단기보호 등이 포함된다. 방문요양은 장기요양요원이 수급자의 가정을 방문하여 신체활동 및 가사활동을 지원하는 서비스이며, 방문간호는 간호사 등이 의사 지시서(방문간호지시서)에 따라 방문하여 간호·진료 보조·요양 상담 등을 제공하는 서비스다. 시설급여와 달리 수급자가 자택 생활을 유지하면서 필요한 서비스를 받는 방식이다.','보장',array['재가급여','방문요양','방문간호','주야간보호','장기요양'],'cycle2_mined','cycle2_mined','노인장기요양보험법 제23조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 노인장기요양보험 (easylaw.go.kr)','ai_draft','high','admin'),
('term','특별현금급여','노인장기요양보험에서 도서·벽지 거주, 천재지변 등 불가피한 사유로 재가급여·시설급여 이용이 어려운 경우 현금으로 지급되는 급여이다. 가족요양비(제24조)·특례요양비(제25조)·요양병원간병비(제26조)의 3종으로 구성된다. 가족요양비는 가족이 직접 돌볼 때 지급되며(가족요양보호사 요건 충족 시), 요양병원간병비는 장기요양기관이 아닌 요양병원 입원 시 지급된다.','보장',array['특별현금급여','가족요양비','요양병원간병비','특례요양비','장기요양','현금급여'],'cycle2_mined','cycle2_mined','노인장기요양보험법 제24조·제25조·제26조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 노인장기요양보험 (easylaw.go.kr)','ai_draft','high','admin'),
('term','장기요양인정점수','노인장기요양보험에서 장기요양등급 판정의 기준이 되는 점수로, 신체기능·인지기능·행동변화·간호처치·재활 등 영역에 걸친 90개 조사 항목 중 52개 항목에 대한 방문 인정조사 결과를 입력하여 산출한다. 점수에 따라 1~5등급 및 인지지원등급이 부여되며, 같은 점수라도 치매 여부 등 상태에 따라 등급이 달라질 수 있다(예: 5등급·인지지원등급은 치매 환자만 해당).','보장',array['장기요양인정점수','52개 항목','등급판정','장기요양인정조사','노인장기요양'],'cycle2_mined','cycle2_mined','노인장기요양보험법 시행규칙 별지 제5호서식 장기요양인정조사표 (국가법령정보센터 law.go.kr); 국민건강보험공단 장기요양보험 (longtermcare.or.kr)','ai_draft','medium','admin'),
('term','CDR척도(임상치매척도)','치매의 중증도를 평가하는 임상 도구로, 기억력·지남력·판단력 및 문제해결·지역사회 활동·가정생활 및 취미·자기관리 6개 영역을 0(정상), 0.5(의심), 1(경증), 2(중등도), 3(중증)으로 평가한다. 보험약관상 경증치매(CDR 1점) 또는 중증치매(CDR 2점 이상) 진단비 지급기준으로 활용되는 경우가 많으며, 치매 관련 보험금 청구 시 핵심 진단 기준 중 하나이다. CDR-SOB(Sum of Boxes)는 6개 영역 점수의 합산으로 0~18점 범위이며 중증도 세분화에 활용된다.','보장',array['CDR척도','임상치매척도','치매 진단','경증치매','중증치매','CDR-SOB'],'cycle2_mined','cycle2_mined','중앙치매센터 CDR 척도 안내 (nid.or.kr); 생명보험사 치매간병보험 상품현황 (생명보험협회 klia.or.kr)','ai_draft','high','admin'),
('term','치매(Dementia)','치매관리법 제2조제1호에 따르면 퇴행성 뇌질환 또는 뇌혈관계 질환 등으로 인하여 기억력·언어능력·지남력(指南力)·판단력 및 수행능력 등의 기능이 저하됨으로써 일상생활에서 지장을 초래하는 후천적인 다발성 장애를 말한다. 보험 약관상 치매 진단은 전문의(신경과·정신건강의학과 등)에 의한 임상적 진단이 필요하며, CDR 척도 등의 기준이 적용될 수 있다.','보장',array['치매','치매관리법','CDR','기억력','보험금','지남력'],'cycle2_mined','cycle2_mined','치매관리법 제2조제1호 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','간병보험','보험업감독규정 별표에서 정의하는 인보험의 한 종류로, 치매 또는 일상생활장해 등 타인의 간병을 필요로 하는 상태 및 이로 인한 치료 등의 위험에 대해 금전 및 그 밖의 급여를 지급할 것을 약속하고 대가를 수수하는 보험이다. 질병보험과 구분되며, 장기요양상태 진입 또는 치매 진단 시 진단비·일당 형태로 보험금이 지급된다.','보장',array['간병보험','일상생활장해','치매','장기요양','인보험'],'cycle2_mined','cycle2_mined','보험업감독규정 별표 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 (easylaw.go.kr)','ai_draft','medium','admin'),
('term','일상생활장해(ADL 장해)','간병보험·장기요양보험에서 보험금 지급 요건으로 활용되는 개념으로, 식사·배변·이동·목욕·옷 입기 등 기본적인 일상생활 동작(Activities of Daily Living, ADL)을 스스로 수행하지 못하는 상태를 말한다. 보험약관에 따라 5~6개 ADL 항목 중 일정 수 이상에서 도움이 필요한 상태가 지급 기준이 되며, 간병보험의 핵심 지급 요건이다. 구체적인 항목 수 기준 및 도움 필요 정도는 보험회사별 약관에서 달리 정할 수 있으므로, 청약 전 해당 약관을 반드시 확인해야 한다.','보장',array['일상생활장해','ADL','간병보험','장기요양','식사 배변 이동'],'cycle2_mined','cycle2_mined','금융감독원 생명보험 표준약관 (보험업감독업무시행세칙 별표15, fss.or.kr); 법제처 찾기쉬운 생활법령 인보험 종류(easylaw.go.kr)','ai_draft','medium','admin'),
('term','유병력자보험(간편심사보험)','과거 병력이 있거나 현재 질환을 앓고 있어 일반 보험 가입이 어려운 자를 위한 보험으로, 간소화된 건강고지 항목만으로 가입 심사를 진행한다. 금융감독원 및 생명보험협회는 이를 ''간편심사보험'' 또는 ''유병자보험''으로 분류하여 상품현황을 공시하며, 일반 보험 대비 보험료가 높고 보장 범위가 제한될 수 있다. 고지항목 수는 상품 및 보험사별로 상이하므로 약관 확인이 필요하다.','인수',array['유병력자보험','간편심사보험','유병자보험','병력','고지의무'],'cycle2_mined','cycle2_mined','생명보험협회 공시 「생명보험사 치매간병/유병자 보험 상품현황」(klia.or.kr); 보험업감독규정(국가법령정보센터 law.go.kr)','ai_draft','medium','admin'),
('term','선지급서비스','생명보험 표준약관에서 인정하는 서비스로, 피보험자가 말기암 등 여명이 얼마 남지 않은 말기질환 상태로 진단받았을 때 사망보험금의 일부를 생전에 미리 지급받을 수 있는 제도이다. 수령한 금액은 사망 시 지급될 보험금에서 차감되며, 피보험자의 치료비·생활비 등에 활용된다. 구체적인 말기질환 범위 및 여명 기간 기준은 보험사별 약관에 따라 다를 수 있으므로 해당 약관 확인이 필요하다.','보장',array['선지급서비스','말기질환','사망보험금 선지급','여명','생명보험'],'cycle2_mined','cycle2_mined','생명보험 표준약관 (보험업감독업무시행세칙 별표15, 국가법령정보센터 law.go.kr); 금융감독원 금융소비자보호(fss.or.kr)','ai_draft','medium','admin'),
('term','체증형 보장','보험 가입 후 경과 연수나 일정 기간마다 보험가입금액(보장금액)이 증가하는 방식이다. 인플레이션이나 치료비 상승에 대응하기 위해 보장금액이 매년 일정 비율로 증가하도록 설계된다. 종신보험·CI보험·간병보험 등에 체증형 특약으로 부가되는 경우가 많으며, 보험가입금액이 고정되는 평준형과 대비되는 개념이다.','계약',array['체증형','보장금액 증가','인플레이션','체증형 종신보험','평준형'],'cycle2_mined','cycle2_mined','금융감독원 파인 보험상품 비교공시 (fine.fss.or.kr); 생명보험협회 팩트북(klia.or.kr)','ai_draft','high','admin'),
('term','체감형 보장','보험 가입 후 경과 연수나 일정 기간마다 보험가입금액(보장금액)이 감소하는 방식이다. 주로 대출 잔액에 연동하여 감액되는 주택담보대출 관련 사망보험, 또는 생애주기에 따라 필요 보장금액이 줄어드는 구조 설계에 활용된다. 체증형의 반대 개념이다.','계약',array['체감형','보장금액 감소','모기지보험','대출연계보험','생명보험'],'cycle2_mined','cycle2_mined','금융감독원 파인 보험상품 안내 (fine.fss.or.kr); 생명보험협회 소비자 안내(klia.or.kr)','ai_draft','high','admin'),
('term','종신보험의 정기보험 전환','종신보험 계약자가 일정 시점 이후 보험료 납입 부담을 줄이기 위해 종신 보장을 정기 보장으로 전환하는 계약 변경 방식이다. 생명보험 표준약관에는 보험료 납입이 어려울 경우 해약환급금을 재원으로 하여 보험료 납입 없이 보험기간 동안 보장을 유지하는 ''감액완납보험''으로 변경하거나, 보험금을 낮추는 방식의 계약 변경이 규정되어 있다. 단, ''종신 보장을 정기 보장으로 직접 전환''하는 방식은 개별 보험사 약관 및 상품 구조에 따라 가능 여부가 다르므로 해당 약관 확인이 필요하다.','계약',array['종신보험 전환','정기보험 전환','계약 변경','감액완납','보험료 절감'],'cycle2_mined','cycle2_mined','생명보험 표준약관 계약 변경 조항 (보험업감독업무시행세칙 별표15, law.go.kr); 보험업감독규정(law.go.kr)','ai_draft','medium','admin'),
('term','연금전환 특약','생명보험 계약의 보험금 또는 해약환급금을 연금으로 전환할 수 있도록 하는 특약이다. 특약에서 정한 연령에 도달하면 잔존 보험가입금액이나 해약환급금을 재원으로 하여 연금 지급을 개시할 수 있다. 종신보험·CI보험 등에 부가되어 노후 소득으로 전환하는 기능을 하며, 연금 개시 가능 연령 및 조건은 보험사별 약관에 따라 다르므로 개별 약관 확인이 필요하다.','계약',array['연금전환','연금전환 특약','생명보험 연금','노후소득','해약환급금'],'cycle2_mined','cycle2_mined','생명보험 표준약관 및 금융감독원 표준약관 목록 (fss.or.kr); 통합연금포털(금융감독원 fss.or.kr)','ai_draft','medium','admin'),
('term','저축성보험 비과세 요건','소득세법 시행령 제25조에 따라 저축성보험의 보험차익(이자소득)이 비과세되기 위한 요건으로, 보험계약기간이 10년 이상이고 납입 보험료 합계가 1억 원 이하인 경우, 또는 최초납입일부터 납입기간이 5년 이상인 월적립식 저축성보험으로서 매월 납입 보험료가 150만 원 이하인 경우에 해당한다. 이 요건을 충족하지 않으면 보험차익에 이자소득세가 부과된다.','세제',array['저축성보험 비과세','보험차익','10년 이상','1억원 한도','이자소득세','월 150만원'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조 (국가법령정보센터 law.go.kr); 국세청 금융소득 과세 안내(nts.go.kr)','ai_draft','high','admin'),
('term','타인의 생명보험(피보험자 서면동의)','상법 제731조 제1항에 따라 타인의 사망을 보험사고로 하는 생명보험 계약을 체결할 때에는 반드시 피보험자(타인)의 서면 동의를 보험계약 체결 시까지 받아야 한다. 이 서면동의 요건은 강행규정으로서 위반 시 계약이 확정적으로 무효가 되며, 사후 추인에 의해서도 유효로 될 수 없다(대법원 2006. 4. 27. 선고 2003다60259 판결 등). 도박보험 방지, 피보험자 살해 위험 방지, 공서양속 보호가 입법 취지이다.','계약',array['타인의 생명보험','피보험자 동의','서면동의','상법 731조','계약 무효'],'cycle2_mined','cycle2_mined','상법 제731조 제1항 (국가법령정보센터 law.go.kr); 대법원 2003다60259 판결 (law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','보험수익자 변경권','상법 제733조 제1항에 따라 보험계약자는 보험수익자를 지정하거나 변경할 수 있는 형성권을 가진다. 이 권리는 보험자나 보험수익자의 동의 없이 자유롭게 행사할 수 있으며, 변경의 효력은 즉시 발생한다. 단, 상법 제734조 제1항에 따라 변경 사실을 보험자에게 통지하지 않으면 보험자에게 대항할 수 없다. 또한 타인의 사망을 보험사고로 하는 계약에서 수익자를 변경할 때에는 피보험자의 서면동의가 필요하다(상법 제734조 제2항).','계약',array['보험수익자 변경','수익자 지정','상법 733조','형성권','보험계약'],'cycle2_mined','cycle2_mined','상법 제733조·제734조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 보험계약자 권리(easylaw.go.kr)','ai_draft','high','admin'),
('term','순수보장형','보험기간 만료 시 생존 환급금이 없는 보장성 보험으로, 납입 보험료 전액이 위험보장에 사용된다. 만기환급형에 비해 같은 보장 조건에서 보험료가 저렴하지만 만기 시 환급금이 없다. 금융감독원 파인(fine.fss.or.kr) ''쉽게 보는 보험상식''에서 보장성 보험의 하위 분류로 설명된다.','계약',array['순수보장형','만기환급 없음','보장성보험','보험료 저렴','만기환급형 비교'],'cycle2_mined','cycle2_mined','금융감독원 파인 쉽게 보는 보험상식 (fine.fss.or.kr/main/prc/is/sub/is005.jsp); 법제처 찾기쉬운 생활법령 보험상품 구분(easylaw.go.kr)','ai_draft','high','admin'),
('term','단기납(短期納)','보험의 보장기간보다 짧은 기간 동안 보험료를 납입하는 방식이다. 예를 들어 종신보험의 보장기간은 평생이지만 보험료는 10년납·20년납 등 일정 기간만 납입하는 경우가 해당된다. 납입기간이 짧을수록 매월 보험료는 높아지지만 총납입보험료가 적을 수 있고, 납입 완료 후 보험료 부담이 없어진다. 금융감독원 파인 보험 기본사항 체크리스트에서 납입기간 확인 항목으로 언급된다.','계약',array['단기납','납입기간','10년납','20년납','종신납'],'cycle2_mined','cycle2_mined','금융감독원 파인 보험 가입 전 주요 체크사항 (fine.fss.or.kr/main/prc/is/sub/is003.jsp)','ai_draft','high','admin'),
('term','위험보험료','생명보험료를 구성하는 요소 중 하나로, 사망·질병·상해 등 보험사고 발생 시 보험금 지급을 위해 적립하는 보험료 부분이다. 보험료는 위험보험료·저축보험료·부가보험료(사업비)로 구성되며, 위험보험료는 예정위험률을 기초로 산출된다. 연령이 높을수록 위험보험료가 증가하며, 갱신형 보험에서 보험료 인상의 주된 원인이 된다.','계약',array['위험보험료','보험료 구성','예정위험률','저축보험료','부가보험료'],'cycle2_mined','cycle2_mined','금융감독원 파인 쉽게 보는 보험상식 (fine.fss.or.kr/main/prc/is/sub/is005.jsp); 생명보험협회 팩트북(klia.or.kr)','ai_draft','high','admin'),
('term','예정이율','보험회사가 보험료 산출 시 적용하는 예상 투자수익률로, 보험계약자로부터 수취한 보험료를 운용하여 얻을 것으로 예상하는 이율이다. 예정이율이 높을수록 보험료가 낮아지고, 낮을수록 보험료가 높아진다. 금리 변화에 따라 예정이율이 조정될 수 있으며, 최저보증이율과는 구별된다.','계약',array['예정이율','보험료 산출','금리','예정위험률','예정사업비'],'cycle2_mined','cycle2_mined','금융감독원 파인 쉽게 보는 보험상식 (fine.fss.or.kr/main/prc/is/sub/is005.jsp); 보험개발원 통계(kidi.or.kr)','ai_draft','high','admin'),
('term','보험수익자의 사전지정(지정대리청구인과의 차이)','보험수익자는 보험금을 수령할 자로서 상법 제733조 제1항에 따라 보험계약자가 지정·변경한다. 보험계약자가 지정권을 행사하지 않고 사망한 때에는 같은 조 제2항에 따라 피보험자가 보험수익자가 된다. 지정대리청구인이 보험금 청구를 대리하는 역할인 것과 달리, 보험수익자는 보험금 수령 권리 자체를 갖는 자이다. 특히 사망보험의 경우 피보험자와 수익자를 달리 지정할 수 있어 상속설계에 활용된다.','계약',array['보험수익자','수익자 지정','상법 733조','지정대리청구인 차이','상속설계'],'cycle2_mined','cycle2_mined','상법 제733조 제1항·제2항 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','장기요양기관','노인장기요양보험법 제31조에 따라 장기요양급여를 제공하는 기관으로, 시설급여를 제공하는 노인요양시설·노인요양공동생활가정과 재가급여를 제공하는 방문요양기관·방문목욕기관·주야간보호센터 등이 있다. 시설급여 기관뿐 아니라 재가급여 기관도 특별자치시장·특별자치도지사·시장·군수·구청장의 지정을 받아야 운영할 수 있으며(제31조 지정 단일화 규정), 보험 약관상 장기요양기관 입소·이용이 보험금 지급 요건으로 명시되는 경우가 있다.','보장',array['장기요양기관','노인요양시설','주야간보호','방문요양기관','시설급여'],'cycle2_mined','cycle2_mined','노인장기요양보험법 제31조 (국가법령정보센터 law.go.kr); 국민건강보험공단 노인장기요양보험(longtermcare.or.kr)','ai_draft','high','admin'),
('term','표준장기요양이용계획서','노인장기요양보험법 제17조에 따라 국민건강보험공단이 등급판정 심의 완료 후 수급자에게 발급·송부하는 문서로, 급여 종류별 월 한도액·본인부담률 등을 기재하여 장기요양급여를 합리적으로 이용할 수 있도록 작성된 계획서이다. 장기요양기관은 수급자와 계약을 체결할 때 이 계획서를 바탕으로 장기요양급여 제공 계획서를 작성하여 국민건강보험공단에 통보해야 하며, 기관 계약 및 서비스 이용의 기초 자료가 된다.','보장',array['표준장기요양이용계획서','등급판정','수급자','서비스 계획','장기요양'],'cycle2_mined','cycle2_mined','노인장기요양보험법 제17조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 노인장기요양보험(easylaw.go.kr)','ai_draft','high','admin'),
('term','보장성보험과 저축성보험의 구분','보장성 보험은 위험보장을 주목적으로 하며, 사고·질병·사망 등 발생 시 보험금이 지급되고 만기 시 환급금이 없거나 납입 보험료 이하이다. 저축성 보험은 위험보장보다 목돈 마련·노후 대비를 주목적으로 하며 만기 시 상당한 환급금이 지급된다. 소득세법상 보장성 보험료에 대해서만 세액공제가 적용된다.','계약',array['보장성보험','저축성보험','만기환급금','세액공제','보험 구분'],'cycle2_mined','cycle2_mined','금융감독원 파인 보험상품 안내 (fine.fss.or.kr/main/prc/is/sub/is005.jsp); 법제처 찾기쉬운 생활법령 보험상품 구분(easylaw.go.kr)','ai_draft','high','admin'),
('term','질병보험','보험업감독규정 제1-2조의2 별표 1에서 정의하는 인보험으로, 사람의 질병 또는 질병으로 인한 입원·수술 등의 위험(질병으로 인한 사망 위험은 제외)에 대해 보험금을 지급하는 보험이다. 간병보험과 달리 질병 자체 또는 질병으로 인한 의료 행위를 보장 대상으로 하며, CI보험·암보험·뇌혈관보험 등이 이 범주에 포함된다.','보장',array['질병보험','인보험','입원수술','CI보험','암보험'],'cycle2_mined','cycle2_mined','보험업감독규정 제1-2조의2 및 별표 1 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','medium','admin'),
('term','상피내암(Carcinoma in Situ)','악성 종양세포가 상피 내에만 존재하고 기저막을 침범하지 않은 단계의 초기 암으로, 일반 생명보험 약관에서 일반 암 진단비보다 낮은 금액의 소액암(유사암) 진단비를 지급한다. 지급 비율은 상품·약관에 따라 다르며, 통상 일반 암 진단비의 10~20% 수준으로 설계되는 경우가 많다. CI보험의 중대한 암 정의에서는 제외되는 경우가 많아, 상피내암 진단 시 일반 암 진단비와 CI 보험금 수령 가능 여부를 구분하여 안내할 필요가 있다.','보장',array['상피내암','소액암','유사암','CI보험 제외','암진단비','기저막'],'cycle2_mined','cycle2_mined','보험업감독업무시행세칙 별표15 생명보험표준약관 암 분류 기준 (금융감독원, fss.or.kr); 보험연구원 암보험 관련 주요 분쟁사례 연구(kiri.or.kr)','ai_draft','medium','admin'),
('term','뇌혈관질환(I60~I67)','보험약관 및 의료 기준에서 뇌혈관 관련 보험금 지급의 기준이 되는 KCD 질병 코드 구간으로, 지주막하출혈(I60), 뇌내출혈(I61), 기타 비외상성 두개내출혈(I62), 뇌경색증(I63), 출혈 또는 경색증으로 명시되지 않은 뇌졸중(I64), 뇌경색증을 유발하지 않은 뇌전동맥의 폐쇄 및 협착(I65), 뇌경색증을 유발하지 않은 대뇌동맥의 폐쇄 및 협착(I66), 기타 뇌혈관질환(I67)이 포함된다. 건강보험 본인부담금 산정특례 뇌혈관질환 범위(별첨1)로도 공식 사용된다.','보장',array['뇌혈관질환','I60~I67','뇌졸중 코드','뇌경색','뇌출혈','산정특례'],'cycle2_mined','cycle2_mined','본인일부부담금 산정특례에 관한 기준 별첨1 뇌혈관질환 상병코드(I60~I67) (국가법령정보센터 law.go.kr); 생명보험협회 뇌혈관질환 보장 상품현황(klia.or.kr)','ai_draft','high','admin'),
('term','경증치매 진단비','치매 진단을 받았으나 중증에 이르지 않은 경증 단계에서 지급되는 진단비이다. 보험사마다 약관에서 정하는 경증치매의 기준이 다를 수 있으며, CDR(임상치매척도) 척도·간이정신상태검사(MMSE) 등을 복합 적용한다. 통상적으로 CDR 1점 수준을 경증치매 기준으로 설정하는 상품이 많으나, 이는 법령이 아닌 개별 약관에서 정하는 사항이다. 치매관리법(법 제2조)은 치매를 ''기억력 등 인지기능 저하로 일상생활에 지장을 초래하는 후천적 다발성 장애''로 정의하며 경증·중증 단계를 법령으로 구분하지 않는다. 중증치매 진단비보다 보험금이 낮게 설정되는 경우가 많으며 조기 치매 대비를 위한 보장이다.','보장',array['경증치매','치매진단비','CDR','MMSE','조기 치매','치매관리법'],'cycle2_mined','cycle2_mined','치매관리법 제2조 (국가법령정보센터 law.go.kr); 생명보험협회 공시 「생명보험사 치매간병보험 상품현황」(klia.or.kr)','ai_draft','medium','admin'),
('term','간이정신상태검사(MMSE)','치매 선별 및 중증도 평가에 사용되는 표준화된 인지기능 검사 도구로, 지남력·기억력·주의력·언어능력·시공간 구성 능력 등을 30점 만점으로 평가한다. 치매 보험금 지급 기준으로 CDR과 함께 또는 단독으로 사용되는 경우가 있다. 한국에서는 연령·학력·성별에 따른 보정 규준점수를 적용하는 MMSE-DS(한국형 간이정신상태검사)가 공식 선별 도구로 쓰이며(중앙치매센터 기준), 국제적으로 24점 미만을 인지저하 의심, 18점 미만을 중등도 이상으로 분류하는 기준이 참고되나 이는 개인별 특성에 따라 다르게 적용된다.','보장',array['MMSE','간이정신상태검사','치매','인지기능','CDR','MMSE-DS'],'cycle2_mined','cycle2_mined','치매관리법 제2조 및 치매관리종합계획(easylaw.go.kr); 중앙치매센터(nid.or.kr); 생명보험협회 치매간병보험 상품현황(klia.or.kr)','ai_draft','medium','admin'),
('term','가족요양비','노인장기요양보험의 특별현금급여 중 하나로, 도서·벽지 등 장기요양기관이 현저히 부족한 지역 거주자, 천재지변으로 장기요양기관 이용이 어려운 사람, 감염병 환자, 정신장애인 등 보건복지부령으로 정하는 사유에 해당하는 수급자가 가족으로부터 방문요양에 상당하는 장기요양급여를 받는 경우 국민건강보험공단이 현금으로 지급하는 급여이다(노인장기요양보험법 제24조). 재가급여·시설급여와 중복 수급은 원칙적으로 금지된다.','보장',array['가족요양비','특별현금급여','장기요양','도서벽지','가족 간병','노인장기요양보험법 제24조'],'cycle2_mined','cycle2_mined','노인장기요양보험법 제24조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','시설급여','노인장기요양보험에서 장기요양 수급자가 노인요양시설·노인요양공동생활가정 등 장기요양기관에 장기간 입소하여 신체활동 지원 및 심신기능의 유지·향상을 위한 교육·훈련 등을 제공받는 급여이다(노인장기요양보험법 제23조). 재가급여와 달리 시설에 입소하는 형태이며, 비용의 일부를 수급자가 본인부담금으로 부담한다.','보장',array['시설급여','노인요양시설','장기요양','입소','본인부담금','노인장기요양보험법 제23조'],'cycle2_mined','cycle2_mined','노인장기요양보험법 제23조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','보험계약의 무효','보험계약 체결 당시 이미 보험사고가 발생하였거나 발생할 수 없는 것인 때에는 그 계약은 무효로 한다. 단, 당사자 쌍방과 피보험자 모두가 이를 알지 못한 때에는 무효가 되지 않는다(상법 제644조). 즉 당사자(보험계약자·보험자) 중 어느 한 쪽이라도 또는 피보험자가 이를 알았다면 계약은 무효가 된다. 또한 타인의 사망을 보험사고로 하는 계약에서 피보험자의 서면 동의가 없는 경우(상법 제731조), 사기에 의한 초과보험(상법 제669조)도 무효 사유에 해당한다. 무효는 처음부터 계약 효력이 발생하지 않는다는 점에서 해지·취소와 구별된다.','계약',array['보험계약 무효','상법 644조','기왕사고','서면동의 없음','계약 효력'],'cycle2_mined','cycle2_mined','상법 제644조·제669조·제731조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','medium','admin'),
('term','보험자대위(제3자에 대한 대위)','상법 제682조에 따라 손해가 제3자의 행위로 인하여 발생한 경우, 보험금을 지급한 보험자는 지급한 금액의 한도에서 피보험자가 제3자에 대해 가지는 손해배상청구권을 취득하는 제도이다. 이는 피보험자가 보험금과 손해배상금을 이중으로 수령하는 이득을 방지하고, 책임 있는 제3자가 책임을 면하지 못하도록 하기 위한 것이다. 생명보험·상해보험 등 정액보험에는 이중이득 방지 원리가 적용되지 않으므로 보험자대위가 적용되지 않는다.','보장',array['보험자대위','상법 682조','제3자','손해배상청구권','이중이득 금지','정액보험'],'cycle2_mined','cycle2_mined','상법 제682조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','납입면제(보험료 납입 면제)','피보험자가 보험기간 중 약관에서 정한 특정 사유(80% 이상 고도장해, 말기암 진단, 특정 중대질병 진단 등 약관별로 다름)에 해당하는 경우 이후의 보험료 납입이 면제되는 제도이다. 납입 면제 후에도 보험계약은 유지되며 보험금 지급사유 발생 시 정상적으로 보험금이 지급된다. 생명보험 표준약관 및 특약(보험업감독업무시행세칙 별표15)에서 규정된다.','계약',array['납입면제','보험료 납입 면제','고도장해','말기암','중대질병'],'cycle2_mined','cycle2_mined','생명보험 표준약관 납입면제 조항 (보험업감독업무시행세칙 별표15, law.go.kr); 금융감독원 표준약관(fss.or.kr)','ai_draft','high','admin'),
('term','뇌혈관질환 진단비','뇌혈관질환(KCD I60~I67, 지주막하출혈·뇌내출혈·뇌경색증·기타뇌혈관질환 포함)을 보장 대상으로 하는 진단비 특약이다. CI보험의 ''중대한 뇌졸중''이 신경학적 영구 결손을 요건으로 하는 것과 달리, 뇌혈관질환 진단비는 일반질병(GI) 방식으로 진단 확정만으로 지급되는 경우가 일반적이다. 다만 정확한 지급 요건은 개별 약관에 따른다. 생명보험협회는 뇌혈관질환 보장 주요 보험상품 현황을 공시한다.','보장',array['뇌혈관질환 진단비','뇌경색','뇌출혈','GI 방식','뇌졸중 보험','KCD I60~I67'],'cycle2_mined','cycle2_mined','생명보험협회 공시 「뇌혈관질환 보장 주요 보험상품 현황」(klia.or.kr); KCD 분류 I60~I67 (건강보험심사평가원·law.go.kr 고시)','ai_draft','high','admin'),
('term','상법 제730조(생명보험자의 책임)','상법 제730조에 따라 생명보험계약의 보험자는 피보험자의 사망·생존·생사에 관한 보험사고가 발생할 경우 약정한 보험금을 지급할 의무를 진다. 이 조항은 생명보험 계약의 기본 구조와 보험자 책임의 법적 근거를 규정하며, 생명보험에서는 사망뿐 아니라 생존 또는 생사를 보험사고로 할 수 있음을 명시한다.','계약',array['상법 730조','생명보험자 책임','사망보험','생존보험','생사보험'],'cycle2_mined','cycle2_mined','상법 제730조 (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','연금계좌세액공제','소득세법 제59조의3에 따라 종합소득이 있는 거주자가 연금저축계좌 및 퇴직연금계좌(IRP)에 납입한 금액에 대해 세액을 공제하는 제도이다. 연금저축계좌 연간 600만원, 퇴직연금계좌 합산 900만원까지 공제 대상이며, 총급여 5,500만원(종합소득 4,500만원) 이하 시 15%, 초과 시 12%의 세액공제율이 적용된다.','세제',array['연금저축','IRP','세액공제','연말정산','소득세법 59조의3'],'cycle2_mined','cycle2_mined','소득세법 제59조의3(연금계좌세액공제) (국가법령정보센터 law.go.kr); 국세청 연금계좌 세액공제 안내(nts.go.kr)','ai_draft','high','admin'),
('term','세제적격연금','납입 시 세액공제(EET 방식) 혜택을 받는 대신, 수령 시 연금소득세가 과세되는 연금상품 유형이다. 대표적으로 연금저축보험·연금저축펀드·IRP가 해당한다. 소득세법 제59조의3에 따라 연간 최대 900만원까지 세액공제를 받을 수 있으나, 연금 수령 시 소득세법 제20조의3에 따라 연금소득세(만 55~69세 5.5%, 만 70~79세 4.4%, 만 80세 이상 3.3%, 지방세 포함)가 부과된다. 요건 미충족 중도인출 시에는 기타소득세(16.5%, 지방세 포함)가 부과된다.','세제',array['세제적격','연금저축','EET','세액공제','연금소득세','IRP'],'cycle2_mined','cycle2_mined','소득세법 제20조의3(연금소득), 제59조의3(연금계좌세액공제) (국가법령정보센터 law.go.kr); 국세청 연금소득 원천징수(nts.go.kr)','ai_draft','medium','admin'),
('term','세제비적격연금','납입 시 세액공제 혜택이 없는 대신, 일정 요건 충족 시 수령 단계에서 비과세(TEE 방식)를 적용받는 연금상품 유형이다. 대표적으로 연금보험(생명보험사 판매)이 해당한다. 소득세법 시행령 제25조에 따라 월적립식의 경우 납입기간 5년 이상·월 보험료 150만원 이하·유지기간 10년 이상을 충족하면, 일시납의 경우 2017년 4월 1일 이후 계약은 계약자 1인당 납입 합계 1억원 이하·유지기간 10년 이상을 충족하면 보험차익이 이자소득에서 제외되어 비과세된다.','세제',array['세제비적격','연금보험','TEE','비과세','저축성보험','소득세법 시행령 25조'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조(저축성보험의 보험차익) (국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','저축성보험 비과세','소득세법 제16조 제1항 및 시행령 제25조에 따라, 저축성보험의 보험차익이 이자소득에서 제외되는 비과세 혜택. 월적립식의 경우 납입기간 5년 이상·유지기간 10년 이상·월 기본보험료 균등 납입·월납 보험료 합계 150만원 이하, 일시납의 경우 유지기간 10년 이상·납입금액 1억원 이하(2017.4.1. 이후 계약)의 요건을 모두 충족해야 한다.','세제',array['저축성보험','비과세','보험차익','소득세법시행령','10년유지'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조 제3항 (국가법령정보센터)','ai_draft','high','admin'),
('term','보험차익 과세','저축성보험에서 보험금·환급금이 기납입보험료를 초과하는 부분(보험차익)을 이자소득으로 보아 소득세를 과세하는 제도. 소득세법 제16조 제1항 제9호에 근거하며, 비과세 요건(10년 유지, 한도 등)을 충족하지 못한 경우 이자소득세율 14%(지방소득세 포함 15.4%)로 원천징수된다.','세제',array['보험차익','이자소득','원천징수','저축성보험','15.4%'],'cycle2_mined','cycle2_mined','소득세법 제16조 제1항 제9호 (국가법령정보센터)','ai_draft','high','admin'),
('term','연금소득세','연금계좌(연금저축·IRP)에서 연금 형태로 수령할 때 부과되는 세금. 소득세법 제129조 및 시행령에 따라 수령 연령에 따라 차등 적용되며, 55세 이상 70세 미만 5.5%, 70세 이상 80세 미만 4.4%, 80세 이상 3.3%(지방소득세 포함)의 세율로 원천징수된다. 연간 사적연금 합계 1,500만원 초과 시 종합과세 또는 15% 분리과세를 선택할 수 있다.','세제',array['연금소득세','연금수령','원천징수','분리과세','종합과세'],'cycle2_mined','cycle2_mined','소득세법 제129조 제1항 제5호의2, 소득세법 시행령 (국가법령정보센터·국세청)','ai_draft','medium','admin'),
('term','연금외수령','연금계좌에서 연금 형태가 아닌 일시금 또는 연금수령한도를 초과하여 인출하는 행위. 소득세법 시행령 제40조의2에 따라 연금수령한도 초과분은 연금외수령으로 간주되며, 세액공제를 받은 납입액 및 운용수익에 대해 기타소득세 16.5%(지방소득세 포함)가 부과되고 분리과세로 종결된다.','세제',array['연금외수령','기타소득세','16.5%','중도해지','연금계좌'],'cycle2_mined','cycle2_mined','소득세법 시행령 제40조의2, 소득세법 제129조 제1항 (국가법령정보센터)','ai_draft','high','admin'),
('term','과세이연','현재 발생한 소득에 대한 과세 시점을 미래로 늦추는 세제 혜택. 퇴직연금(IRP)·연금저축의 납입 및 운용 단계에서는 과세하지 않고, 실제 수령 시점에 과세하는 방식이다. 운용기간 중 이연된 세금이 재투자되어 복리 효과가 발생하며, 연금 형태로 수령 시 퇴직소득세 감면 혜택도 추가로 받을 수 있다.','세제',array['과세이연','퇴직연금','IRP','연금저축','복리효과'],'cycle2_mined','cycle2_mined','소득세법 제22조, 근로자퇴직급여보장법 (국가법령정보센터)','ai_draft','high','admin'),
('term','사적연금 종합과세','연간 사적연금 수령액이 1,500만원을 초과할 경우 적용되는 과세 방식. 소득세법 제64조의4에 따라 1,500만원 초과 시 납세자가 종합과세(다른 소득과 합산, 누진세율 적용)와 15% 분리과세 중 유리한 방법을 선택할 수 있다. 2024년부터 분리과세 기준금액이 기존 1,200만원에서 1,500만원으로 상향되었다.','세제',array['사적연금','종합과세','분리과세','1500만원','연금소득'],'cycle2_mined','cycle2_mined','소득세법 제64조의4(연금소득에 대한 세액 계산의 특례) (국가법령정보센터)','ai_draft','high','admin'),
('term','금융소득종합과세','연간 이자소득과 배당소득의 합계가 2,000만원을 초과할 경우, 초과분을 다른 종합소득과 합산하여 누진세율(6%~45%, 지방소득세 포함 시 6.6%~49.5%)로 과세하는 제도. 소득세법 제14조에 근거하며, 2,000만원 이하분은 원천징수세율(14%, 지방세 포함 15.4%)로 분리과세하고, 초과분에만 종합과세가 적용된다.','세제',array['금융소득종합과세','이자소득','배당소득','2000만원','누진세율'],'cycle2_mined','cycle2_mined','소득세법 제14조(과세표준의 계산), 제55조(세율) (국가법령정보센터)','ai_draft','medium','admin'),
('term','즉시연금','목돈을 일시에 납입하고 즉시 또는 단기간 후부터 연금을 수령하는 저축성보험 상품. 종신형·확정기간형·상속형 등으로 구분된다. 소득세법 시행령 제25조에 따라 종신형은 요건 충족 시 금액 제한 없이 비과세, 상속형·확정기간형은 계약자 1인당 납입금액 1억원 이하이고 10년 이상 유지 시 비과세가 적용된다.','세제',array['즉시연금','일시납','종신형','상속형','비과세'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조 제3항, 제4항 (국가법령정보센터)','ai_draft','high','admin'),
('term','종신형 연금보험 비과세','소득세법 시행령 제25조 제4항에 따라, 계약자·피보험자·수익자가 동일하고, 55세 이후 사망 시까지 연금으로만 수령하며, 연금 외 지급이 없고, 사망 시 보험계약 및 연금재원이 소멸하며, 최초 연금지급개시 이후 중도해지가 불가능한 경우 납입금액 한도 없이 보험차익이 비과세되는 특례.','세제',array['종신형연금','비과세','계약자피보험자수익자동일','연금개시','소득세법시행령'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조 제4항 (국가법령정보센터)','ai_draft','high','admin'),
('term','연금수령한도','연금계좌에서 연금소득세율(3.3~5.5%)을 적용받기 위해 인출 가능한 연간 최대 금액. 소득세법 시행령 제40조의2에 따라 ''연금계좌 평가금액 ÷ (11 - 연금수령연차) × 120%''로 계산한다. 연금수령연차 11년차 이상에는 한도 제한이 없어 전액 연금수령으로 간주된다. 이 한도를 초과하여 인출하면 연금외수령으로 간주되어 기타소득세 16.5%가 적용된다.','세제',array['연금수령한도','연금수령연차','연금외수령','소득세법시행령','연금계좌'],'cycle2_mined','cycle2_mined','소득세법 시행령 제40조의2 제3항 (국가법령정보센터)','ai_draft','high','admin'),
('term','연금계좌 납입한도','연금저축계좌와 퇴직연금계좌(IRP)를 포함한 연금계좌의 연간 납입 가능 총한도. 소득세법 시행령 제40조의2 제2항에 따라 연간 1,800만원을 초과하여 납입할 수 없다. 이 중 세액공제 대상 납입액은 소득세법 제59조의3에 따라 연금저축계좌 연간 600만원, 연금저축계좌와 퇴직연금계좌(IRP) 합산 연간 900만원으로 별도 제한된다.','세제',array['연금계좌','납입한도','1800만원','세액공제한도','IRP'],'cycle2_mined','cycle2_mined','소득세법 시행령 제40조의2 제2항(납입한도), 소득세법 제59조의3(세액공제한도) (국가법령정보센터·국세청)','ai_draft','medium','admin'),
('term','퇴직소득 분류과세','퇴직소득을 다른 종합소득과 합산하지 않고 별도로 세액을 계산하는 과세 방식. 소득세법 제22조 및 제48조에 근거하며, 근속연수공제 후 환산급여를 산출하고 환산급여공제를 적용하여 최종 세액을 계산한다. 퇴직소득이 클수록 장기 근속자에게 유리한 구조로 설계되어 있다.','세제',array['퇴직소득','분류과세','근속연수공제','환산급여','소득세법'],'cycle2_mined','cycle2_mined','소득세법 제22조(퇴직소득), 제48조(퇴직소득공제) (국가법령정보센터)','ai_draft','high','admin'),
('term','보장성보험 세액공제','근로소득이 있는 거주자가 기본공제대상자를 피보험자로 하는 보장성보험(만기환급금이 납입보험료를 초과하지 않는 보험)에 납입한 보험료에 대해 연 100만원 한도로 12%의 세액공제를 적용하는 제도. 소득세법 제59조의4(특별세액공제)에 근거하며, 장애인전용보장성보험은 별도로 연 100만원 한도 15% 세액공제가 추가 적용된다.','세제',array['보장성보험','세액공제','연말정산','100만원한도','소득세법','장애인전용보험'],'cycle2_mined','cycle2_mined','소득세법 제59조의4(특별세액공제) (국가법령정보센터); 국세청 의료비·보험료 세액공제 (nts.go.kr)','ai_draft','high','admin'),
('term','공적연금 소득세 과세','국민연금·공무원연금·군인연금·사학연금 등 공적연금을 수령할 때 부과되는 소득세. 소득세법 제20조의3에 따라 2002년 1월 1일 이후 납입 기여금 및 사용자 부담금에 기초한 연금액만 연금소득으로 과세된다. 2001년 이전 납입분은 당시 소득공제 혜택이 없었으므로 수령 시에도 비과세된다.','세제',array['공적연금','국민연금','연금소득세','2002년기준','소득세법'],'cycle2_mined','cycle2_mined','소득세법 제20조의3(연금소득), 소득세법 시행령 제40조 (국가법령정보센터); 국세청 연금소득의 범위 (nts.go.kr)','ai_draft','high','admin'),
('term','사망보험금 간주상속재산','피상속인의 사망으로 지급되는 생명보험금이 상속재산으로 간주되어 상속세가 과세되는 제도. 상속세 및 증여세법 제8조에 따라 피상속인이 보험계약자이거나 실질적으로 보험료를 납부한 경우, 수익자가 받는 사망보험금은 상속재산으로 본다. 과세 대상 보험금 가액은 ''지급받은 보험금 합계액 × (피상속인이 부담한 보험료 / 납입 보험료 총합계액)''의 비율로 산정된다.','세제',array['사망보험금','간주상속재산','상속세','상증세법','피상속인','보험료비율'],'cycle2_mined','cycle2_mined','상속세 및 증여세법 제8조(상속재산으로 보는 보험금) (국가법령정보센터); 국세청 상속재산가액 (nts.go.kr)','ai_draft','medium','admin'),
('term','보험금의 증여','보험료 납부자와 보험금 수령인이 다를 경우 경제적 이익이 무상 이전된 것으로 보아 증여세를 부과하는 규정. 상속세 및 증여세법 제34조에 따라 보험금 수령인이 납부자가 납부한 보험료에 해당하는 보험금 상당액을 증여재산으로 본다. 수익자를 자녀로 하고 부모가 보험료를 납부한 경우 증여세 과세 대상이 될 수 있다. 단, 보험금이 상속재산으로 과세된 경우에는 증여세를 중복 과세하지 않는다.','세제',array['보험금증여','증여세','수익자','보험료납부자','상증세법'],'cycle2_mined','cycle2_mined','상속세 및 증여세법 제34조(보험금의 증여) (국가법령정보센터); 국세청 국세법령정보시스템 질의회신 (taxlaw.nts.go.kr)','ai_draft','high','admin'),
('term','월적립식 저축성보험 비과세 한도','소득세법 시행령 제25조 제3항에 따른 월적립식 저축성보험의 비과세 적용 요건 중 납입금액 기준. 2017년 4월 1일 이후 체결 계약의 경우 계약자 1인당 매월 납입하는 보험료 합계액이 150만원 이하여야 한다. 납입기간 5년 이상, 유지기간 10년 이상 요건을 함께 충족해야 하며, 150만원 초과 시 보험차익 전액이 이자소득으로 과세된다.','세제',array['월적립식','비과세한도','150만원','저축성보험','소득세법시행령'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조 제3항 제1호 (국가법령정보센터)','ai_draft','high','admin'),
('term','일시납 저축성보험 비과세 한도','소득세법 시행령 제25조 제3항에 따른 일시납 저축성보험의 비과세 적용 납입금액 상한. 2017년 4월 1일 이후 체결 계약의 경우 계약자 1인당 납입금액이 1억원 이하이고 10년 이상 유지 시 보험차익이 이자소득에서 제외된다. 2017년 3월 31일 이전 계약은 한도가 2억원이었다.','세제',array['일시납','비과세한도','1억원','저축성보험','소득세법시행령'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조 제3항 제2호 (국가법령정보센터)','ai_draft','high','admin'),
('term','이자소득 분리과세','이자소득·배당소득(금융소득)의 합계가 연간 2,000만원 이하인 경우 다른 소득과 합산하지 않고 원천징수로 과세를 종결하는 방식(소득세법 제14조 제3항). 소득세법 제129조에 따라 이자소득에 대한 원천징수세율은 14%(지방소득세 포함 시 15.4%)가 적용된다. 저축성보험 보험차익이 비과세 요건을 충족하지 못할 경우 이 세율로 원천징수된다.','세제',array['이자소득','분리과세','원천징수','15.4%','소득세법','금융소득','2000만원'],'cycle2_mined','cycle2_mined','소득세법 제129조(원천징수세율), 제14조 제3항(과세표준의 계산) (국가법령정보센터); 국세청 금융소득 과세대상 (call.nts.go.kr)','ai_draft','medium','admin'),
('term','확정기간형 연금','연금 수령 기간을 계약 시 미리 확정(5년·10년·20년 등)하고, 해당 기간 동안만 연금을 지급받는 연금 지급 유형. 수령 중 사망 시 잔여 연금은 수익자에게 계속 지급된다(보증기간 내 사망 시 잔여 기간 지급 보증). 세제비적격 연금보험에서 주로 선택할 수 있으며, 비과세 요건(10년 이상 유지 등)을 충족한 경우 수령액은 이자소득세가 과세되지 않는다.','세제',array['확정기간형','연금수령','연금보험','비과세','보증기간','사망시잔여연금'],'cycle2_mined','cycle2_mined','법제처 찾기쉬운 생활법령정보 — 사적연금제도 > 연금보험 (easylaw.go.kr); 소득세법 시행령 제25조(국가법령정보센터)','ai_draft','medium','admin'),
('term','상속형 연금','적립금의 원금은 유지하고 운용수익(이자)만을 연금으로 지급하는 즉시연금 유형. 가입자 사망 시 원금이 소멸되지 않고 상속인에게 이전되어 상속 설계 목적으로 활용된다. 비과세 요건(소득세법 시행령 제25조 제3항 — 납입 1억원 이하·10년 이상 유지 등 일시납 요건)을 충족하면 운용수익 수령액이 비과세될 수 있다. 사망 시 잔여 원금은 상속세 및 증여세법에 따라 상속세 과세 대상이 될 수 있다.','세제',array['상속형연금','즉시연금','상속설계','원금보전','비과세','이자수령'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조 제3항 제2호 (국가법령정보센터); 상속세 및 증여세법 제8조(국가법령정보센터)','ai_draft','medium','admin'),
('term','연금소득 종합신고','사적연금 수령액이 연간 1,500만원을 초과하는 경우 다음 해 5월에 종합소득세 확정신고를 하거나 15% 분리과세를 선택해야 한다. 소득세법 제64조의4(연금소득에 대한 세액 계산의 특례) 및 제14조에 근거하며, 1,500만원 초과 시 15% 분리과세 또는 다른 소득과 합산한 종합과세 중 납세자가 유리한 방법을 선택할 수 있다. 2023년 1월 1일 이후 연금수령분부터 기준금액이 기존 1,200만원에서 1,500만원으로 상향되었다.','세제',array['종합소득세신고','사적연금','1500만원','분리과세선택','5월신고'],'cycle2_mined','cycle2_mined','소득세법 제64조의4(연금소득에 대한 세액 계산의 특례), 제14조(과세표준의 계산) (국가법령정보센터); 국세청 연금소득 원천징수/분리과세 (nts.go.kr)','ai_draft','high','admin'),
('term','연금수령 개시 요건','연금계좌에서 연금소득세(3.3~5.5%)를 적용받아 연금으로 인출하기 위한 법정 요건. 소득세법 시행령 제40조의2 제3항에 따라 만 55세 이상이어야 하고, 연금계좌 가입일로부터 5년 이상 경과해야 하며, 연금수령 개시를 금융기관에 신청한 후 인출해야 한다. 단, 이연퇴직소득이 포함된 경우에는 5년 경과 요건이 적용되지 않는다. 또한 연금수령연차가 11년 이상이 되면 연금수령한도 제한도 적용되지 않는다.','세제',array['연금수령개시','55세이상','5년경과','이연퇴직소득','소득세법시행령'],'cycle2_mined','cycle2_mined','소득세법 시행령 제40조의2 제3항 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','ISA 비과세','개인종합자산관리계좌(ISA)에서 발생한 순이익에 대한 비과세 혜택. 조세특례제한법 제91조의18에 따라 일반형은 200만원, 서민형·농어민형(총급여 5,000만원 이하 또는 종합소득 3,800만원 이하)은 400만원까지 비과세되며, 초과분에는 9.9% 분리과세가 적용된다. 만기 ISA를 연금계좌로 전환 시 추가 세액공제 혜택도 부여된다. ※ 2025년 12월 현재 한도를 500만원·1,000만원으로 확대하는 개정안은 국회 본회의를 통과하지 못해 현행 한도가 유지되고 있다.','세제',array['ISA','비과세','200만원','400만원','분리과세','서민형','농어민형'],'cycle2_mined','cycle2_mined','조세특례제한법 제91조의18 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','비과세 종신보험','보장성보험으로서 피보험자 사망 시 보험금을 지급하는 종신보험이 저축성보험(보험차익 과세 대상)에 해당하는지 여부와 비과세 조건에 관한 개념. 순수보장형(만기환급금이 없거나 납입보험료 이하)은 보험차익이 발생하지 않아 과세 문제가 없으나, 환급금이 납입보험료를 초과하면 저축성보험으로 보아 소득세법 시행령 제25조의 비과세 요건을 충족해야 한다. 비과세 요건: 최초 보험료 납입일로부터 만기일 또는 중도해지일까지 10년 이상 유지, 2017년 4월 1일 이후 체결 계약은 1인당 납입보험료 합계 1억원 이하(2017년 3월 31일 이전은 2억원 이하).','세제',array['종신보험','비과세','저축성보험','보장성보험','보험차익','10년유지'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조(저축성보험의 보험차익) (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','연금저축 중도해지 과세','세액공제를 받은 연금저축보험·연금저축펀드를 55세 이전 또는 연금 형태가 아닌 방식으로 해지할 때 부과되는 세금. 세액공제 받은 납입원금과 운용수익 전액에 대해 기타소득세 16.5%(지방소득세 포함)가 원천징수되며 분리과세로 종결된다. 사망·해외이주·3개월 이상 요양 등 부득이한 사유 시에는 연금소득세(3.3~5.5%)가 적용된다.','세제',array['연금저축해지','기타소득세','16.5%','부득이한사유','중도해지'],'cycle2_mined','cycle2_mined','소득세법 제59조의3, 소득세법 시행령 제40조의2 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','EET 과세 방식','연금 과세 체계 중 납입(Exempt)·운용(Exempt)·수령(Tax) 단계에서 납입과 운용 시 비과세하고 수령 시 과세하는 방식. 세제적격 연금저축·IRP·퇴직연금이 이 방식을 따른다. 납입 시 세액공제를 통해 세부담을 낮추는 대신, 연금 수령 시 연금소득세(3.3~5.5%)가 부과된다. 다만 우리나라는 엄밀히는 납입 시 ''소득공제''가 아닌 ''세액공제'' 방식을 적용하므로 순수 EET와 다소 차이가 있다는 지적도 있다.','세제',array['EET','과세방식','연금저축','세액공제','연금소득세','세제적격'],'cycle2_mined','cycle2_mined','기획재정부 시사경제용어사전 EET항목(moef.go.kr), 보험연구원 KIRI 보고서','ai_draft','medium','admin'),
('term','TEE 과세 방식','연금 과세 체계 중 납입(Tax)·운용(Exempt)·수령(Exempt) 단계에서 납입 시 과세하고 운용·수령 시 비과세하는 방식. 세제비적격 연금보험이 이 방식을 따른다. 납입 시 세액공제 혜택이 없는 대신, 소득세법 시행령 제25조 요건 충족 시(10년 이상 유지, 납입한도 이하 등) 보험차익이 이자소득에서 제외되어 수령 시 비과세된다.','세제',array['TEE','과세방식','연금보험','비과세수령','세제비적격'],'cycle2_mined','cycle2_mined','기획재정부 시사경제용어사전 TEE항목(moef.go.kr), 소득세법 시행령 제25조 (국가법령정보센터 law.go.kr)','ai_draft','medium','admin'),
('term','장애인전용보장성보험 세액공제','기본공제 대상 장애인을 피보험자 또는 수익자로 하는 장애인전용보장성보험에 납입한 보험료에 대한 세액공제. 소득세법 제59조의4 제1항 제2호에 따라 연간 납입액 100만원 한도로 15%의 세액공제율이 적용된다. 일반 보장성보험 세액공제(100만원 한도, 12%)와 별도로 중복 적용 가능하다. 단, 보험계약 또는 납입영수증에 ''장애인전용''으로 표시된 상품에 한정되며, 장애인이 단순히 가입한 일반 보장성보험은 해당되지 않는다.','세제',array['장애인보험','세액공제','15%','100만원한도','특별세액공제'],'cycle2_mined','cycle2_mined','소득세법 제59조의4 제1항 제2호 (국가법령정보센터 law.go.kr), 국세청 의료비·보험료 세액공제 안내(nts.go.kr)','ai_draft','high','admin'),
('term','연금계좌 이체','연금수령 개시 전에 하나의 연금계좌에 있는 금액을 다른 연금계좌로 이전하는 행위. 소득세법 시행령 제40조의4에 따라 연금수령 개시 전 다른 연금계좌로의 이체는 원칙적으로 인출로 보지 않으며, 과세 없이 계좌 간 이전이 가능하다. 단, 다음의 경우는 인출로 간주되어 과세가 발생한다: 1) 연금저축계좌와 퇴직연금계좌(IRP) 상호 간의 이체, 2) 2013년 3월 1일 이후 가입한 계좌의 금액을 2013년 3월 1일 이전 가입 계좌로 이체, 3) 퇴직연금계좌 내 일부 금액만 이체하는 경우. 따라서 동일 유형(연금저축→연금저축, IRP→IRP) 간 전액 이체는 과세 없이 가능하나, 연금저축↔IRP 간 이체는 원칙적으로 인출로 보므로 주의가 필요하다.','세제',array['연금계좌이체','계좌이전','과세없이이전','소득세법시행령','연금저축','IRP'],'cycle2_mined','cycle2_mined','소득세법 시행령 제40조의4(연금계좌의 이체) (국가법령정보센터 law.go.kr)','ai_draft','medium','admin'),
('term','확정급여형 퇴직연금(DB형)','사용자가 부담금을 사외 적립하여 운용하고, 근로자가 퇴직 시 사전에 확정된 급여(통상 최종 평균임금 × 근속연수)를 받는 퇴직연금 제도. 근로자퇴직급여보장법 제2조에 따라 정의되며, 적립금은 사용자가 운용한다. 퇴직 시 수령하는 급여는 퇴직소득으로 분류과세되며, IRP로 이전 시 과세이연이 가능하다.','세제',array['DB형','확정급여형','퇴직연금','사용자부담','과세이연'],'cycle2_mined','cycle2_mined','근로자퇴직급여보장법 제2조(정의) (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','확정기여형 퇴직연금(DC형)','사용자가 매년 근로자 연간 임금총액의 12분의 1 이상을 근로자 개인 계좌에 납입하고 근로자가 직접 운용하는 퇴직연금 제도. 근로자퇴직급여보장법 제20조에 근거한다. 근로자 본인도 별도 추가 부담금을 납입할 수 있으며, 연금계좌(DC+IRP+연금저축 합산) 납입 한도는 연간 1,800만원이다. 이 중 연금저축과 IRP(또는 DC 개인납입분)를 합산하여 최대 900만원까지 세액공제 대상이 된다(소득세법 제59조의3). 운용수익은 연금 수령 시까지 과세이연된다.','세제',array['DC형','확정기여형','퇴직연금','세액공제','근로자운용','연금계좌'],'cycle2_mined','cycle2_mined','근로자퇴직급여보장법 제20조(확정기여형 부담금), 소득세법 제59조의3(연금계좌 세액공제) (국가법령정보센터 / 국세청)','ai_draft','medium','admin'),
('term','연금보험 계약자 변경과 증여세','저축성 생명보험의 계약자를 타인으로 변경하는 행위는 보험의 실질적 소유권 이전으로 간주되어 증여세 과세 대상이 될 수 있다. 상속세 및 증여세법에 따라 변경 시점의 해약환급금 상당액이 증여재산가액으로 산정된다. 단순한 피보험자·수익자 변경은 증여세 과세 대상이 아니다. 보험 계약자 명의 변경 시 보험회사는 관할 세무서에 명의변경 내용을 제출할 의무가 있다.','세제',array['계약자변경','증여세','해약환급금','저축성보험','상증세법','명의변경'],'cycle2_mined','cycle2_mined','상속세 및 증여세법 제34조(보험금의 증여), 국세청 서면 유권해석, 보험 계약자 명의변경 명세서 제출요령 (국가법령정보센터 / 국세청)','ai_draft','high','admin'),
('term','공시이율','보험회사가 금리연동형 저축성보험·연금보험의 적립금에 적용하는 이율로, 매월 시장금리와 운용자산이익률 등을 반영하여 공시하는 이율. 보험업감독규정 및 생명보험협회 상품통일공시기준에 따라 운용자산이익률과 외부지표금리를 가중 평균하여 산출한다. 공시이율 변동에 관계없이 보험회사가 보증하는 최저한도는 최저보증이율이다.','계약',array['공시이율','금리연동','저축성보험','연금보험','최저보증이율'],'cycle2_mined','cycle2_mined','보험업감독규정, 생명보험협회 상품공시기준 (금융감독원 / 생명보험협회)','ai_draft','high','admin'),
('term','연금보험 납입기간 5년 요건','월적립식 저축성보험의 보험차익 비과세를 적용받기 위한 요건 중 하나. 소득세법 시행령 제25조 제3항에 따라 최초 납입일부터 납입기간이 5년 이상이어야 하며, 만기일 또는 중도해지일까지의 기간이 10년 이상이어야 한다. 아울러 계약자 1명당 월 보험료 합계액이 150만원 이하이어야 한다(2017년 4월 1일 이후 계약). 세 가지 요건 중 하나라도 충족하지 못하면 보험차익 전액에 이자소득세가 과세된다.','세제',array['납입기간5년','비과세요건','월적립식','소득세법시행령','저축성보험','월150만원'],'cycle2_mined','cycle2_mined','소득세법 시행령 제25조 제3항 제1호 (국가법령정보센터)','ai_draft','medium','admin'),
('term','임원 퇴직소득 한도','법인 임원에게 지급하는 퇴직급여 중 소득세법상 퇴직소득으로 인정받을 수 있는 상한. 소득세법 시행령 제105조에 따라, 2020년 1월 1일 이후 근무기간에 대해서는 퇴직 전 3년 평균 급여 × (1/10) × 근속연수 × 2배를 초과하는 금액은 근로소득으로 과세된다(2020년 이전 기간분은 3배 배수 적용). 초과분은 퇴직소득이 아닌 근로소득으로 분류되어 종합과세 대상이 된다.','세제',array['임원퇴직금','퇴직소득한도','법인세','근로소득','소득세법시행령','2배배수'],'cycle2_mined','cycle2_mined','소득세법 시행령 제105조(임원 퇴직소득금액 한도), 국세청 임원 퇴직소득금액 안내 (국가법령정보센터 / 국세청)','ai_draft','high','admin'),
('term','연금저축 부득이한 사유 인출','연금저축·IRP를 연금 개시 요건 충족 이전 또는 연금 외 형태로 인출하더라도 낮은 연금소득세율(3.3~5.5%)을 적용받을 수 있는 법정 예외 사유. 소득세법 시행령에 따라 천재지변, 가입자 또는 부양가족의 3개월 이상 요양, 재난으로 15일 이상 입원치료 필요, 가입자 사망·해외이주, 가입자 파산선고 또는 개인회생 절차 개시, 연금계좌 취급자의 영업정지·인허가취소·파산이 해당한다.','세제',array['부득이한사유','연금저축','IRP','연금소득세','중도인출','요양','파산'],'cycle2_mined','cycle2_mined','소득세법 시행령 제40조의2 제4항 (국가법령정보센터 / 국세청)','ai_draft','high','admin'),
('term','위법계약해지권','금융상품판매업자등이 6대 판매원칙(적합성·적정성·설명의무·불공정영업금지·부당권유금지·광고규제)을 위반하여 계약을 체결한 경우, 일반금융소비자가 수수료·위약금 없이 해당 계약의 해지를 요구할 수 있는 권리다. 위반사실을 안 날로부터 1년 이내에 요구해야 하며, 해당 기간은 계약체결일로부터 5년 이내의 범위 안에 있어야 한다. 금융회사는 요구 접수일로부터 10일 이내에 수락 여부를 통지해야 하며, 거절할 때에는 거절 사유를 함께 통지해야 한다.','민원',array['위법계약해지','금소법','판매원칙위반','해지권','소비자권리','1년행사기간'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제47조 (국가법령정보센터 / 법제처 찾기쉬운 생활법령)','ai_draft','high','admin'),
('term','소액분쟁 조정이탈금지','일반금융소비자가 분쟁조정을 신청한 사건에서 조정 대상 금액이 2천만 원 이하(대통령령으로 정하는 금액 이하)인 소액분쟁사건에 대해서는 금융회사(조정대상기관)가 조정안 제시 전에 소를 제기할 수 없도록 금지한 제도. 금융소비자보호법 제42조에 근거하며, 일반금융소비자의 분쟁조정을 통한 권리 구제를 실질적으로 보장하기 위한 취지다.','민원',array['소액분쟁','조정이탈금지','분쟁조정','금소법','2천만원','소제기금지'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제42조 (국가법령정보센터)','ai_draft','high','admin'),
('term','자료열람요구권','일반금융소비자가 분쟁조정 또는 소송 등 권리구제 목적으로 금융상품판매업자등이 기록·유지·관리하는 자료의 열람(사본 제공·청취 포함)을 요구할 수 있는 권리. 금융소비자보호법 제28조에 근거하며, 계약 체결·이행 자료, 광고 자료, 소비자 권리행사 자료 등이 대상이다. 금융회사는 요구받은 날로부터 6영업일 이내에 열람하게 해야 하며, 영업비밀 침해 우려 등 법정 제한 사유가 있는 경우 거절 또는 제한이 가능하다.','민원',array['자료열람','열람요구권','금소법','분쟁조정','소비자권리','6영업일'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제28조 제1항·제3항 및 시행령 제26조 (국가법령정보센터 / 법제처 찾기쉬운 생활법령)','ai_draft','high','admin'),
('term','설명의무 위반 손해배상 입증책임 전환','금융소비자보호법 제44조는 금융상품판매업자등이 설명의무를 위반하여 소비자에게 손해를 입힌 경우, 금융회사가 고의·과실 없음을 스스로 입증해야 하도록 입증책임을 전환했다. 민법상 불법행위에서는 피해자가 가해자의 고의·과실을 증명해야 하지만, 금소법은 이를 뒤집어 소비자 보호를 강화했다. 또한 금융상품판매대리·중개업자의 위법행위로 소비자에게 손해가 발생한 경우 직접판매업자도 연대 책임을 질 수 있다.','민원',array['입증책임전환','설명의무','손해배상','금소법제44조','과실추정','연대책임'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제44조 제2항 (국가법령정보센터)','ai_draft','high','admin'),
('term','과징금(금소법)','금융상품직접판매업자 또는 금융상품자문업자가 6대 판매원칙 등 주요 규정을 위반한 경우 위반행위로 얻은 수입(보장성 상품의 경우 수입보험료 기준)의 최대 50%까지 부과할 수 있는 행정제재. 금융소비자보호법 제57조에 근거하며, 위반 중대성에 따라 부과기준율을 세분화한다. 과태료와 별도로 병과된다.','판매',array['과징금','금소법','수입50%','판매원칙위반','행정제재'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제57조 (국가법령정보센터)','ai_draft','high','admin'),
('term','과태료(금소법)','금융소비자보호법상 판매원칙 위반 시 부과되는 금전적 행정제재. 위반 행위 유형에 따라 부과 상한이 다르며, 설명의무 위반 등의 경우 개인(설계사)은 최대 3,000만 원, 법인(GA 등)은 최대 7,000만 원이 부과될 수 있다. 허위·과장 광고 등 일부 중대 위반의 경우 개인 5,000만 원, 법인 1억 원 한도이다. 과징금과 별도로 병과 가능하다. 금융소비자보호법 제69조에 근거한다.','판매',array['과태료','금소법','행정제재','설계사','GA','허위광고'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제69조 (국가법령정보센터)','ai_draft','medium','admin'),
('term','해피콜(완전판매모니터링)','보험회사가 계약 청약 확정 후 일정 시간이 경과한 뒤 계약자·피보험자에게 전화(또는 e-모니터링)로 접촉하여, 설명 내용 이해 여부·자필서명 이행 여부 등 완전판매 준수 사항을 확인하는 제도다. 2026년 4월부터 청약 확정 후 3시간이 경과한 이후에만 실시 가능하도록 개편됐으며, 불완전판매 예방이 목적이다. 3시간 이전 소비자가 먼저 연락하더라도 진행이 불가하며, 이메일·SNS 등을 활용한 e-모니터링도 동일 기준이 적용된다.','판매',array['해피콜','완전판매모니터링','불완전판매예방','보험모집','전화확인','3시간'],'cycle2_mined','cycle2_mined','보험업감독규정 개정(금융위원회고시 제2026-1호, 2026.1.2. 시행) / 금융위원회 입법예고 자료 (fsc.go.kr) 및 다자비 보험AI뉴스(dazabi.com) 보도 확인','ai_draft','high','admin'),
('term','미스터리쇼핑(금융감독원)','금융감독원이 외부 조사업체를 활용하여 금융회사 영업점에 일반 고객으로 위장 방문하거나 전화하여 금융상품 판매 과정의 적합성 원칙·설명의무 준수 여부 등을 불시 점검하는 제도다. 보험업권에서는 생명보험사·손해보험사 대상으로 정기·비정기 실시하며 결과를 공시한다. 미스터리쇼핑은 법령에 직접 명시된 제도라기보다는 금감원이 금융소비자 보호에 관한 법률 제51조(금융소비자보호 실태평가) 및 감독 권한에 근거하여 운영하는 행정적 점검 수단이다.','판매',array['미스터리쇼핑','금감원','불시점검','불완전판매','소비자보호','실태평가'],'cycle2_mined','cycle2_mined','금융감독원 보도자료 및 금융소비자 보호에 관한 법률 제51조 (금감원 fss.or.kr / 국가법령정보센터)','ai_draft','medium','admin'),
('term','일반금융소비자','전문금융소비자가 아닌 모든 금융소비자로, 금융상품에 대한 전문성과 협상력이 상대적으로 낮아 6대 판매원칙·설명의무·청약철회권·위법계약해지권 등 금소법의 핵심 소비자 보호 규정이 전면 적용되는 대상이다. 대부분의 개인 보험계약자가 해당된다.','판매',array['일반금융소비자','금소법','소비자구분','보호대상','전문소비자'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제2조 제9호 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','전문금융소비자','금융상품에 관한 전문성이나 소유 자산규모 등을 고려해 금융상품 계약에 따른 위험을 감수할 능력이 있다고 인정되는 금융소비자로, 국가·지방자치단체·금융회사·주권상장법인 등이 해당된다. 전문금융소비자에게는 설명의무 등 일부 소비자 보호 규정의 적용이 제외 또는 완화된다.','판매',array['전문금융소비자','금소법','소비자구분','상장법인','금융기관'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제2조 제8호 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','불공정영업행위 금지','금융상품판매업자등이 우월적 지위를 이용하여 소비자의 권익을 침해하는 일련의 행위를 금지하는 원칙이다. 구체적 유형으로는 대출 조건으로 특정 상품 가입 강요, 수수료·이자 등 비용 부당 청구, 계약 해지 방해 등이 있으며, 금소법 6대 판매원칙 중 하나다.','판매',array['불공정영업행위','금소법','6대판매원칙','우월적지위','판매금지'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제20조 (국가법령정보센터 law.go.kr) 및 찾기쉬운 생활법령정보 (easylaw.go.kr)','ai_draft','high','admin'),
('term','부당권유행위 금지','금융상품 계약 체결 권유 시 불확실한 사항에 단정적 판단 제공, 허위 사실 고지, 중요 사항 미고지, 근거 없는 비교 광고 등 부당한 권유 행위를 금지하는 원칙이다. 금소법 제21조에서 구체적 행위 유형을 열거하며, 금소법 6대 판매원칙 중 하나다.','판매',array['부당권유금지','금소법','6대판매원칙','단정적판단','허위고지'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제21조 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','광고규제(금소법)','금융상품 광고 시 허위·과장 표현을 금지하고, 보장 한도·면책 사항·이자율 변동 가능성 등 중요 사항을 충분히 표시해야 하는 의무다. 금소법 6대 판매원칙 중 하나(허위·과장광고 금지)이며, 금융업권 협회가 광고를 사전 심의할 수 있다. 위반 시 과태료가 부과되며, 구체적인 과태료 금액은 금소법 과태료 조항(제69조 등) 및 시행령을 직접 확인해야 한다.','판매',array['광고규제','금소법','6대판매원칙','보험광고','광고심의','허위과장광고'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제22조 및 금융상품 등의 표시·광고에 관한 심사지침 (금융위원회·국가법령정보센터 law.go.kr)','ai_draft','medium','admin'),
('term','부당 승환계약 금지','보험모집 종사자가 기존 보험계약을 부당하게 소멸시켜 새 계약을 체결하게 하거나, 새 계약 체결을 위해 기존 계약을 소멸시키는 행위를 금지하는 규정이다. 새 계약 청약일로부터 1개월 이내에 기존 계약이 소멸하거나, 기존 계약 소멸일로부터 1개월 이내에 새 계약을 청약하게 하는 경우 원칙적으로 부당승환으로 간주한다. 위반 시 보험업법 제209조의 과태료 규정에 따라 제재를 받는다. 단, 계약자 본인 의사에 의한 것임을 자필서명 등으로 입증한 경우에는 예외로 한다.','판매',array['부당승환','보험업법','승환계약','기존계약소멸','과태료'],'cycle2_mined','cycle2_mined','보험업법 제97조 제1항 및 제209조(과태료), 보험업법 시행령 (국가법령정보센터 law.go.kr)','ai_draft','medium','admin'),
('term','청약철회 효과(원상회복)','보험 청약철회권 행사 시 계약은 처음부터 없었던 것으로 간주하며, 보험회사는 철회 접수일로부터 3일 이내에 이미 납입한 보험료 전액을 반환해야 한다. 반환이 지연될 경우 해당 기간에 대해 보험계약대출 이율을 연단위 복리로 계산한 이자를 가산하여 지급해야 한다. 단, 신용카드로 납입한 경우에는 매출 취소로 갈음하며 이자를 별도 지급하지 않는다.','계약',array['청약철회효과','보험료반환','원상회복','3일이내반환','이자가산'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제46조 및 시행령 제37조 (국가법령정보센터 law.go.kr) / 찾기쉬운 생활법령정보 (easylaw.go.kr)','ai_draft','high','admin'),
('term','청약철회 제외 계약','보험 청약철회권이 적용되지 않는 예외 계약 유형으로, 건강 상태 진단을 거친 계약, 보험기간이 90일 이내인 단기 계약, 전문보험계약자(전문금융소비자)가 체결한 계약이 해당된다. 이 경우 통상적인 해지 절차를 따라야 하며 청약철회에 따른 보험료 전액 환불이 불가능하다.','계약',array['청약철회제외','건강진단계약','단기보험','전문계약자','예외'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제46조 제3항 및 시행령 제37조 (국가법령정보센터 law.go.kr) / 찾기쉬운 생활법령정보 (easylaw.go.kr)','ai_draft','high','admin'),
('term','금융소비자보호 내부통제기준','금융회사가 금소법에 따라 의무적으로 제정·운영해야 하는 내부 규범으로, 금융상품 판매 시 소비자 보호를 위한 업무 분장·조직 구조·판매 절차·민원 처리 기준 등을 포함한다. 이사회 승인을 받아야 하며(이사회가 없는 경우 대표자 또는 내부 의사결정기구 승인), 위반 시 감독당국의 제재 대상이 된다. 구체적으로 포함되어야 하는 사항은 금융소비자 보호에 관한 감독규정 제9조 및 별표 2에서 정하고 있다.','판매',array['내부통제기준','금소법','금융소비자보호','이사회승인','금융회사의무'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제16조 및 금융소비자 보호에 관한 감독규정 제9조·별표2 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','금융소비자보호 총괄책임자(CCO)','금소법 제30조에 따라 금융회사가 선임해야 하는 금융소비자보호 업무 총괄 임원이다. 소비자 권익 침해 발생 시 대표이사에게 보고할 의무가 있다. 금융감독원 금융소비자보호 모범규준에서는 CCO가 상품위원회에 참여하여 소비자 침해 우려 상품 출시에 의견을 제시하도록 권고하고 있으나, ''당연직 위원으로서의 비토권(거부권)''은 법률 조항에 직접 규정된 내용이 아니라 모범규준·내부통제기준 차원의 권고사항이다.','판매',array['CCO','총괄책임자','금소법','소비자보호임원','모범규준'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제30조 (국가법령정보센터) / 금융소비자보호 모범규준 (금융위원회)','ai_draft','medium','admin'),
('term','금융상품판매대리·중개업자','금소법이 분류하는 금융상품판매업자 유형 중 하나로, 금융상품 직접판매업자를 위해 계약 체결을 대리하거나 중개하는 자다. 보험업에서는 보험대리점(GA)과 보험설계사가 이에 해당하며, 직접판매업자와 달리 일부 과징금 부과 대상에서 제외될 수 있다.','판매',array['판매대리중개업','금소법','보험대리점','GA','보험설계사'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제2조 제3호 (국가법령정보센터)','ai_draft','high','admin'),
('term','독립금융상품자문업자','금소법에 따라 등록된 금융상품자문업자 중 특정 금융상품판매업자와 이해관계 없이 독립적으로 소비자에게 자문을 제공하는 자다. 금융상품판매업 겸영이 금지되며, 금융상품판매업자의 계열회사이거나 임직원을 파견받아서는 안 된다는 요건을 충족해야 한다.','판매',array['독립자문업자','금소법','금융상품자문','이해충돌','독립성'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제12조 (국가법령정보센터) / 독립금융상품자문업 등록 심사 매뉴얼 (금융위원회)','ai_draft','high','admin'),
('term','보험안내자료 준수사항','보험회사가 보험안내자료(상품설명서, 팸플릿 등)를 작성·사용할 때 준수해야 하는 사항으로, 보험업법 제95조 및 보험업감독규정에 따라 중요 내용은 명료하고 알기 쉽게 기재해야 한다. 사이버몰(인터넷) 모집 등에 사용되는 안내자료는 심사를 받은 후 관리번호를 부여받아야 한다. 다만 ''모든 보험안내자료에 보험계리사 또는 상품계리부서 참여 의무화''는 보험업감독규정상 세부 요건을 일반화한 표현이므로 실제 감독규정 원문 확인이 필요하다.','판매',array['보험안내자료','보험업법','관리번호','심사의무','상품설명서'],'cycle2_mined','cycle2_mined','보험업법 제95조 및 보험업감독규정 (국가법령정보센터)','ai_draft','medium','admin'),
('term','통신수단 모집 준수사항','전화·인터넷 등 통신수단을 이용하여 보험을 모집할 경우 계약자의 동의를 받아 청약 내용·보험기간·고지의무·약관 주요 내용 등을 설명하고 답변·확인 내용을 음성녹취해야 한다. 사이버몰(인터넷) 모집 시에는 약관 주요 내용 표시 및 공인전자서명 또는 계약자 확인 절차가 요구된다. 근거 조문은 보험업법 시행령 제43조 및 보험업감독규정 관련 조항이다.','계약',array['통신수단모집','사이버모집','음성녹취','전화보험','보험업법'],'cycle2_mined','cycle2_mined','보험업법 시행령 제43조 및 보험업감독규정 (국가법령정보센터)','ai_draft','high','admin'),
('term','설명서 교부 및 서명 확인','금소법 제19조에 따라 금융상품판매업자등은 계약 체결 권유 시 또는 일반금융소비자의 요청이 있을 때, 중요 사항을 담은 설명서를 제공하고 소비자로부터 설명 이해 여부에 대한 서명·기명날인 또는 녹취로 확인을 받아야 한다. 설명서 앞 부분에는 중요 사항 요약을 포함해야 한다.','판매',array['설명서교부','서명확인','금소법제19조','설명의무','설명확인서'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제19조 (국가법령정보센터)','ai_draft','high','admin'),
('term','특별이익 제공 금지(보험업법)','보험계약 체결·모집과 관련하여 계약자 또는 피보험자에게 금품, 약관 외 보험료 할인, 약관 외 보험금 추가 지급 약속, 보험료 대납 등의 특별이익을 제공하거나 약속하는 행위를 금지한다(보험업법 제98조). 예외적으로 보험계약 체결 시부터 최초 1년간 납입되는 보험료의 100분의 10과 3만원 중 적은 금액, 위험 감소 물품(20만원 한도)은 허용된다(보험업법 시행령 제46조).','판매',array['특별이익금지','보험업법제98조','보험료대납','금품제공','모집금지'],'cycle2_mined','cycle2_mined','보험업법 제98조 및 시행령 제46조 (국가법령정보센터)','ai_draft','medium','admin'),
('term','보험 모집 금지행위(보험업법 제97조)','보험계약 체결·모집 종사자가 해서는 안 되는 행위를 열거한 조항으로, 허위사실 고지, 불확실 사항에 대한 단정적 판단 제공, 기존 계약의 부당한 소멸, 보험계약자·피보험자에게 중요 사항 미고지 등이 포함된다. 특히 기존 보험계약 소멸일로부터 1개월 이내에 신규 계약을 청약하게 하거나, 신규 청약일로부터 1개월 이내에 기존 계약을 소멸시키는 행위는 부당 소멸로 추정된다. 이는 금소법 이전부터 보험업법에서 별도로 규정해 온 보험 모집 특유의 금지 규정이다.','판매',array['모집금지행위','보험업법제97조','단정적판단금지','허위고지금지','부당행위'],'cycle2_mined','cycle2_mined','보험업법 제97조 제1항 (국가법령정보센터)','ai_draft','high','admin'),
('term','금융소비자 정보포털(파인, FINE)','금융감독원이 운영하는 금융소비자 종합 정보 포털(fine.fss.or.kr)로, 금융상품 비교·조회, 민원 신청, 분쟁조정 신청, 보험계약 조회, 휴면보험금 조회 등 다양한 소비자 보호 서비스를 제공한다. 보험 가입 내역 조회 및 실손보험 중복 가입 여부 확인도 가능하다.','민원',array['파인','FINE','금감원포털','보험조회','민원신청'],'cycle2_mined','cycle2_mined','금융감독원 금융소비자정보포털 파인 (fine.fss.or.kr)','ai_draft','high','admin'),
('term','고령금융소비자 보호','금소법 및 금융소비자 보호에 관한 감독규정에 따라 고령금융소비자(65세 이상)에게는 강화된 권유 절차가 적용된다. 금융회사는 판매 시 추가적인 설명 확인 등 보호 조치를 내부통제기준에 반영해야 하며, 금융감독원 모범규준에서는 냉각기간 부여 등을 권고하고 있다. 다만 ''상품 개발 단계에서 고령자 위험요인 점검'' 및 ''냉각기간''의 구체적 적용 방식은 개별 금융회사 내부통제기준 수준에서 정해지므로, 법령상 일률적 의무로 단정하기 어렵다.','판매',array['고령소비자','65세이상','강화권유절차','취약계층','소비자보호'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 감독규정 (국가법령정보센터) / 금융소비자보호 모범규준 (금금융위원회)','ai_draft','medium','admin'),
('term','적정성 원칙(금소법)','일반금융소비자가 자발적으로 구매하려는 금융상품이 해당 소비자의 재산 상황·투자 경험 등에 비추어 적정하지 않다고 판단될 경우, 금융상품판매업자등이 이를 소비자에게 알려야 하는 원칙이다. 적합성 원칙이 ''권유 시'' 적용되는 반면, 적정성 원칙은 ''소비자가 자발적으로 구매 요청할 때'' 적용된다. 적용 대상은 보장성 상품 외에 파생상품·파생결합증권·고난도금융투자상품 등 시행령 제12조 제1항에서 정한 상품을 포함한다.','판매',array['적정성원칙','금소법제18조','6대판매원칙','자발적구매','부적정고지','고난도금융투자상품'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제18조 및 시행령 제12조 (국가법령정보센터)','ai_draft','medium','admin'),
('term','불완전판매비율 공시','보험회사가 판매한 보험계약 중 청약철회·품질보증해지·민원 등으로 불완전판매가 확인된 건수를 전체 신계약 건수 대비 비율로 산출하여 금융감독원 또는 생명보험협회·손해보험협회에 공시하는 제도다. 보험업감독규정에 근거하며, 소비자가 보험사 판매 품질을 비교할 수 있다. ''2016년부터 상품별 불완전판매비율 추가 공시''라는 구체적 연도는 공식 출처로 교차 확인이 필요하다.','판매',array['불완전판매비율','공시','보험협회','금감원','소비자비교'],'cycle2_mined','cycle2_mined','보험업감독규정 (국가법령정보센터) / 생명보험협회·손해보험협회 공시 기준','ai_draft','medium','admin'),
('term','보험 계약 취소(약관설명의무 위반)','보험회사 또는 모집 종사자가 약관의 중요 내용을 설명하지 않거나 청약서에 자필서명을 받지 않은 경우, 보험계약자가 계약 성립 후 3개월 이내에 해당 계약을 취소할 수 있는 권리다. 상법 제638조의3 제2항에 근거하며, 취소 시 납입 보험료 전액을 이자와 함께 돌려받는다.','계약',array['계약취소','약관설명의무위반','상법638조의3','3개월이내','보험료반환'],'cycle2_mined','cycle2_mined','상법 제638조의3 제2항 (국가법령정보센터 상법 보험편)','ai_draft','high','admin'),
('term','금융소비자보호법(금소법) 시행일·배경','2020년 3월 24일 공포(법률 제17112호)되어 2021년 3월 25일 시행된 법률로, 기존에 업권별(은행법·보험업법·자본시장법 등)로 분산되어 있던 금융소비자 보호 규정을 통합하고 강화한 법이다. 6대 판매원칙 도입, 위법계약해지권·청약철회권 확대, 손해배상 입증책임 전환 등을 핵심 내용으로 한다.','판매',array['금소법','금융소비자보호법','2021년시행','6대판매원칙','법령통합','법률제17112호'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 (법률 제17112호, 2020년 3월 24일 공포 — 국가법령정보센터)','ai_draft','high','admin'),
('term','판매원칙 위반과 계약 효력','금소법상 6대 판매원칙 위반 자체가 계약을 당연 무효로 만들지는 않는다. 다만 소비자는 위법계약해지권(제47조) 행사(위반사실을 안 날로부터 1년 이내이자 계약체결일로부터 5년 이내), 손해배상 청구(제44조), 청약철회권(제46조) 등을 통해 구제를 받을 수 있으며, 판매원칙 위반에 대한 행정 제재(과징금·과태료)는 별도로 부과된다.','계약',array['판매원칙위반','계약효력','위법계약해지','손해배상','금소법구제수단','1년이내','5년이내'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제44조·제46조·제47조 (국가법령정보센터)','ai_draft','high','admin'),
('term','보험 완전판매 체크리스트','보험 불완전판매를 사전에 방지하기 위해 보험회사 및 모집 종사자가 계약 체결 시 확인해야 하는 항목들을 표준화한 목록이다. 약관·청약서 교부, 자필서명 여부, 설명의무 이행, 고지의무 안내 등이 포함되며, 완전판매 모니터링(해피콜)의 확인 내용과 연동된다. 해피콜은 보험업감독규정에 근거하여 청약철회 기간 내에 보험모집이 적법하게 이루어졌는지 전화·온라인으로 확인하는 절차다.','판매',array['완전판매체크리스트','불완전판매예방','보험모집','자필서명확인','약관교부','해피콜'],'cycle2_mined','cycle2_mined','보험업법 및 보험업감독규정 (국가법령정보센터) / 금감원 금융상품 공통사항','ai_draft','medium','admin'),
('term','금융소비자 손해배상청구권','금융상품판매업자등이 고의 또는 과실로 금소법을 위반하여 금융소비자에게 손해를 발생시킨 경우, 소비자가 그 손해를 배상받을 수 있는 권리다(금소법 제44조). 설명의무 위반의 경우 과실 입증책임이 금융회사로 전환되며(제44조 제2항), 민법 손해배상 규정(제750조)에 대한 특별법으로 작동한다.','민원',array['손해배상청구권','금소법제44조','설명의무위반','과실추정','소비자권리','입증책임전환'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제44조 (국가법령정보센터)','ai_draft','high','admin'),
('term','금융상품판매업자 배상책임 면제 요건','금소법 제44조에 따라 금융상품판매업자등이 손해배상 책임을 면하려면, 설명의무 위반에 관하여 자신에게 고의 또는 과실이 없었음을 직접 입증해야 한다. 단순히 소비자가 설명을 이해했다고 주장하거나 서명을 받은 사실만으로 면책되지 않으며, 실질적인 설명 이행을 증명해야 한다.','민원',array['배상책임면제','과실없음입증','설명의무','금소법','면책요건','입증책임'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제44조 제2항 (국가법령정보센터)','ai_draft','high','admin'),
('term','금소법 6대 판매원칙 체계','금융소비자보호법이 금융상품 판매 시 판매업자에게 부과하는 6가지 핵심 행위 규범으로, 1) 적합성 원칙(제17조) 2) 적정성 원칙(제18조) 3) 설명의무(제19조) 4) 불공정영업행위 금지(제20조) 5) 부당권유행위 금지(제21조) 6) 광고규제(제22조)로 구성된다. 이 원칙들은 보험·은행·증권 등 모든 금융업권에 통일적으로 적용된다.','판매',array['6대판매원칙','금소법','통일적적용','판매규제','보험적용','제17조','제22조'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제17조~제22조 (국가법령정보센터) / 법제처 찾기쉬운 생활법령정보 — 금융상품 6대 판매원칙','ai_draft','high','admin'),
('term','보험업법상 GA 관리감독 책임','법인보험대리점(GA)은 소속 설계사의 불완전판매·부당 승환·개인정보 유출 등 위반 행위에 대해 기관으로서 관리·감독 책임을 지며, 과태료·영업정지·등록취소 등의 기관 제재를 받을 수 있다. 보험업법 및 보험업감독규정에 근거하며, 금융당국은 GA에 대한 검사·제재를 단순 개인 제재를 넘어 기관 책임 강화 방향으로 운용하고 있다.','판매',array['GA관리책임','법인보험대리점','보험업법','기관제재','감독의무','불완전판매'],'cycle2_mined','cycle2_mined','보험업법 및 보험업감독규정 (국가법령정보센터) / 금감원 GA 검사·제재 기준','ai_draft','high','admin'),
('term','경유계약','실제 보험계약을 모집한 자가 아닌 다른 모집종사자의 명의를 이용하여 보험계약을 체결하는 행위. 보험업법 제97조 제1항 제8호에서 ''다른 모집 종사자의 명의를 이용하여 보험계약을 모집하는 행위''로 명시적으로 금지한다. 위반 시 등록취소·업무정지·과태료 등 행정제재와 형사처벌 대상이 된다. 한편 자격 없는 자에 대한 수수료 지급은 별도의 감독규정 위반 사항으로, 제8호 조문 자체의 내용은 아니다.','판매',array['경유계약','명의대여','모집질서','금지행위','보험업법97조'],'cycle2_mined','cycle2_mined','보험업법 제97조 제1항 제8호 (국가법령정보센터)','ai_draft','medium','admin'),
('term','작성계약','보험계약자의 청약 의사 없이 모집종사자가 임의로 청약서를 작성하여 보험계약을 성립시키는 행위. 실제 명의인의 동의 없는 계약 모집을 금지하는 보험업법 제97조 제1항 제6호, 그리고 허위 내용을 알리는 행위를 금지하는 동조 제1호 등의 금지 행위에 해당한다. 보험사기방지 특별법과도 교차 적용될 수 있으며, 금감원 GA 검사의 중점 적발 항목이다. ''작성계약''은 실무상 통용되는 용어로 법령에 별도 정의 조항이 명시되어 있지는 않다.','판매',array['작성계약','허위청약','모집질서위반','GA검사','보험업법97조'],'cycle2_mined','cycle2_mined','보험업법 제97조 제1항 제1호·제6호 (국가법령정보센터), 보험사기방지 특별법 (국가법령정보센터)','ai_draft','medium','admin'),
('term','가공계약','실제 보험료 납입 의사 없이 수수료 취득을 목적으로 형식적으로만 보험계약을 성립시키는 행위. 계약 조기소멸로 이어지며 보험업법 제97조상 금지행위에 해당하고, 보험사기방지 특별법상 사기행위와 병합 적용될 수 있다. ''가공계약''은 법령에 별도 정의 조항이 없는 실무 용어로, 보험업감독원 검사 및 판례에서 주로 다루어진다.','판매',array['가공계약','수수료사기','모집질서','조기소멸'],'cycle2_mined','cycle2_mined','보험업법 제97조 (국가법령정보센터), 보험사기방지 특별법 (국가법령정보센터)','ai_draft','medium','admin'),
('term','1200% 룰','보험계약 초년도에 설계사 또는 GA에 지급 가능한 수수료 총액(시책비·공통영업비 포함)을 해당 계약 월납보험료의 1200%(12배)로 제한하는 규제. 원래 보험회사 전속 설계사에게 적용됐으나 2026년 7월부터 GA 소속 설계사에게도 확대 적용된다. 확대 적용 시 GA 운영비용의 일정 한도(월납보험료의 3%)는 산정에서 제외될 수 있다.','판매',array['1200%룰','수수료상한','모집수수료','GA수수료','수수료규제'],'cycle2_mined','cycle2_mined','금융위원회 보도자료 ''보험 판매수수료 개편 방안'' (fsc.go.kr), 보험업감독규정','ai_draft','high','admin'),
('term','수수료 분급제','설계사에게 지급하는 모집수수료를 초년도에 일시 지급하지 않고 계약 유지기간에 따라 여러 해에 걸쳐 나눠 지급하는 제도. 금융위원회가 보험업감독규정 개정을 의결하여 2027년 1월부터 4년 분급, 2029년 1월부터 7년 분급으로 단계 확대 시행한다. 계약 유지관리 수수료(유지 시에만 지급)가 신설되고 5~7년차에 장기유지관리 수수료가 추가 지급되어, 계약이 오래 유지될수록 설계사 수령액이 증가하는 구조다. 계약 유지율 제고와 불완전판매 억제가 목적이다.','판매',array['분급제','수수료분할','유지수수료','판매수수료개편'],'cycle2_mined','cycle2_mined','금융위원회 보도자료 ''보험 판매수수료를 분급체계로 개편'' (fsc.go.kr, 2026), 보험업감독규정 개정','ai_draft','high','admin'),
('term','모집수수료 환수','보험계약이 조기 해지·실효·무효·불완전판매 취소 등으로 소멸할 경우 보험회사가 이미 지급한 모집수수료의 일부 또는 전부를 설계사로부터 회수하는 제도. 보험업법 제85조의3 제7호는 정당한 사유 없이 보험설계사에게 지급한 수수료를 환수하는 행위를 금지한다. 계약 소멸에 귀책사유가 인정되는 경우에는 환수가 적법하게 이루어질 수 있다.','판매',array['수수료환수','클로백','조기해약','계약유지율'],'cycle2_mined','cycle2_mined','보험업법 제85조의3 제7호 (국가법령정보센터)','ai_draft','high','admin'),
('term','부당 승환계약','모집종사자가 계약자에게 기존 보험계약과 신규 계약의 보장 내용·보험료·면책기간 재적용 등 중요 사항을 비교 설명하지 않거나 허위로 설명하여 기존 계약을 소멸시키고 신계약을 체결하게 하는 행위. 보험업법 제97조 제3항 제1호는 기존 계약 소멸일부터 1개월 이내 신계약을 청약하게 하거나, 신계약 청약일부터 1개월 이내 기존 계약을 소멸시키는 행위를 부당 승환으로 규정한다. 다만 보험계약자가 손해 발생 가능성을 인지하였음을 자필서명 등 대통령령으로 정하는 방식으로 명백히 증명한 경우에는 예외가 인정된다. 동조 제3항 제2호는 6개월 이내의 전환 시 중요 사항 비교 미설명을 부당 승환으로 규정한다.','판매',array['부당승환','승환계약','보험리모델링','비교설명의무'],'cycle2_mined','cycle2_mined','보험업법 제97조 제3항 (국가법령정보센터)','ai_draft','medium','admin'),
('term','승환계약 비교설명서','기존 계약을 해지하고 새 보험계약을 체결할 때 설계사가 의무적으로 교부해야 하는 서류로, 기존·신규 계약의 보험료 차이·보장 차이·해지 불이익(해약환급금 손실·면책기간 재적용·감액기간 등)을 항목별로 기재한다. 보험업법 제97조 제3항 제2호 및 보험업감독규정에 근거하며, 비교 설명 없이 6개월 이내 승환이 이루어지면 부당 승환으로 간주될 수 있다.','판매',array['비교설명서','승환계약','해지불이익안내','설명의무'],'cycle2_mined','cycle2_mined','보험업법 제97조 제3항 제2호 (국가법령정보센터), 보험업감독규정 (국가법령정보센터)','ai_draft','medium','admin'),
('term','보험료 대납','모집종사자가 계약자를 대신하여 보험료를 납입해주는 행위. 무상 대납은 보험업법 제98조의 특별이익 제공 금지에 해당하여 원칙적으로 금지된다. 다만 반환 의무를 전제로 한 일시적 대납약정은 법원 판례상 즉시 특별이익으로 단정하지 않는 경우도 있으나, 원칙적으로 금지행위로 본다.','판매',array['보험료대납','특별이익','모집금지행위'],'cycle2_mined','cycle2_mined','보험업법 제98조 (국가법령정보센터)','ai_draft','medium','admin'),
('term','자기계약 금지','보험대리점 또는 보험중개사가 자기 또는 자기를 고용하고 있는 자를 보험계약자·피보험자로 하는 보험을 모집하는 것을 주된 목적으로 하지 못하도록 규정한 원칙. 보험업법 제101조에 근거하며, 수수료 수취 목적의 자기계약은 모집질서 위반이자 금감원 검사 중점 항목이다.','판매',array['자기계약금지','자기계약','모집질서','보험업법101조'],'cycle2_mined','cycle2_mined','보험업법 제101조 (국가법령정보센터)','ai_draft','high','admin'),
('term','고지의무 불고지 유도 금지','모집종사자가 보험계약자 또는 피보험자로 하여금 고지해야 할 중요 사항을 보험회사에 알리지 않도록 방해하거나(제97조 제1항 제3호), 허위로 알리도록 권유하는 행위(동항 제4호)를 금지한다. 이는 고지의무 위반과 별개로 모집종사자에게 독립적 제재 사유가 된다.','판매',array['고지의무유도금지','허위고지','모집금지행위','보험업법97조'],'cycle2_mined','cycle2_mined','보험업법 제97조 제1항 제3호·제4호 (국가법령정보센터)','ai_draft','high','admin'),
('term','GA 내부통제기준','소속 설계사 500인 이상 대형 법인보험대리점(GA)에게 보험업감독규정 제4-11조 및 [별표 5의6]에 따라 의무화된 내부통제 기준. 준법감시인 선임, 불건전 영업행위 모니터링, 민원 처리 절차, 설계사 관리 체계 등을 포함하며, 내부통제기준 미비 시 금감원 검사·제재 대상이 된다.','판매',array['GA내부통제','대형GA','준법감시인','보험업감독규정'],'cycle2_mined','cycle2_mined','보험업감독규정 제4-11조 및 [별표 5의6] (국가법령정보센터), 금융위원회 보도자료 ''보험판매채널 소비자최우선'' (fsc.go.kr)','ai_draft','medium','admin'),
('term','GA 판매책임 강화','2026년 금융위원회 보험판매채널 개편 방안에 따라 법인보험대리점(GA)이 소속 설계사의 불완전판매에 대해 직접 책임을 지도록 하는 제도 강화. GA 운영 리스크 평가시스템 도입, GA 운영보증금 한도 상향(최대 5억원), 유지수수료(3~7년) 도입 및 1,200% 룰 적용 등 판매수수료 체계 개편이 포함된다. 보험회사는 위탁 GA의 내부통제 준수 여부를 주기적으로 점검하도록 의무화되며, GA 본점이 지점의 불건전 영업행위를 관리해야 한다.','판매',array['GA판매책임','불완전판매책임','내부통제','채널규제','GA운영리스크평가'],'cycle2_mined','cycle2_mined','금융위원회 보도자료 ''5세대 실손보험 및 기본자본, 판매채널 책임성 강화 등 관련'' (fsc.go.kr, 2026)','ai_draft','high','admin'),
('term','비교설명의무','500인 이상 대형 GA가 대면 모집 시 설계사가 소비자에게 계약 체결 가능한 여러 보험회사의 목록과 상품별 판매수수료 등급·순위를 비교하여 설명해야 하는 의무. 2016년부터 시행되었으며, 2025년 3월부터는 추천 상품의 수수료를 ''매우높음·높음·평균·낮음·매우낮음'' 5단계로 구분해 안내하는 방식으로 강화되었다. 보험업감독규정 [별표5의6]에 규정되며 통신판매·기업성 보험·자동차보험 등은 적용 예외다.','판매',array['비교설명의무','GA비교추천','수수료공시','대형GA','수수료5단계'],'cycle2_mined','cycle2_mined','보험업감독규정 [별표5의6] (국가법령정보센터), 금융위원회 2025~2026 개편안','ai_draft','high','admin'),
('term','불완전판매비율','보험회사나 모집채널의 불완전판매 수준을 측정하는 지표로, (품질보증해지 건수 + 민원해지 건수 + 무효건수) ÷ 신계약 건수 × 100으로 산출한다. 손해보험협회 소비자포털(consumer.knia.or.kr) 등에 공시되며, 금감원 검사 및 GA·설계사 평가 기준으로 활용된다. 2020년 상반기부터 산출 대상 기간이 12개월 기준으로 변경되어 공시된다.','민원',array['불완전판매비율','품질보증해지','민원해지','공시'],'cycle2_mined','cycle2_mined','손해보험협회 소비자포털 불완전판매비율 공시(consumer.knia.or.kr), 보험업감독규정','ai_draft','high','admin'),
('term','보험사기 적발','보험사기방지 특별법에 따라 금융감독원, 보험회사, 수사기관이 보험사기 의심 행위를 조사·적발하는 절차. 금감원 2025년 발표 기준 보험사기 유형별 적발 비중은 사고내용조작(진단서 위변조·과다청구 포함) 약 55%, 허위사고 약 20%, 고의사고 약 15% 순이다. 보험사기 의심 시 건강보험심사평가원에 입원 적정성 심사를 의뢰할 수 있다.','민원',array['보험사기적발','허위입원','고의사고','수사의뢰','사고내용조작'],'cycle2_mined','cycle2_mined','보험사기방지 특별법 제8조 (국가법령정보센터), 금융감독원 2025년 보험사기 적발현황','ai_draft','medium','admin'),
('term','모집종사자 등록·말소','보험설계사, 보험대리점, 보험중개사는 보험업법에 따라 보험협회(생명보험협회·손해보험협회)에 등록해야 영업이 가능하며, 위반 시 보험업법상 결격사유·등록취소·업무정지 처분을 받는다. 해촉 시에는 소속 회사로부터 해촉증명서를 발급받아 협회에 등록 말소를 신청해야 한다.','판매',array['모집종사자등록','설계사등록','말소절차','협회등록'],'cycle2_mined','cycle2_mined','보험업법 제84조·제87조·제89조 (국가법령정보센터), 생명보험협회·손해보험협회 모집종사자 관리시스템','ai_draft','high','admin'),
('term','위촉계약','보험회사 또는 GA가 보험설계사와 모집 위탁을 목적으로 체결하는 계약. 법적 성질은 비전형계약으로 위임·고용·도급이 혼합된 형태로 본다. 보험업법 제85조의3은 위탁계약서상 해지요건 외 사유로 일방적 해지를 금지하고, 설계사의 계약 해지 요청을 정당한 사유 없이 거부하는 것도 금지한다. 또한 정당한 사유 없이 수수료 지급을 거부·지연하거나 지급한 수수료를 환수하는 행위도 금지된다.','판매',array['위촉계약','모집위탁계약','설계사계약','위탁계약해지'],'cycle2_mined','cycle2_mined','보험업법 제85조의3 (국가법령정보센터), 보험연구원 연구보고서 nre2020-08','ai_draft','high','admin'),
('term','해촉','보험회사 또는 GA가 소속 보험설계사와의 위촉계약을 종료하는 행위. 보험업법 제85조의3에 따라 위탁계약서에 정한 해지요건 외 사유로 일방적 해지가 금지되며, 보험업법상 등록취소 사유 해당 시에는 즉시 해촉이 가능하다. 해촉 후에는 보험협회에 등록 말소 절차를 진행해야 한다. ''15일 전 내용증명 발송'' 요건은 보험업법 또는 보험업감독규정 조문에서 직접 확인되지 않으므로 회사 내부 절차 또는 약정에 따른 실무 관행일 수 있다.','판매',array['해촉','위촉계약해지','등록말소','설계사해촉'],'cycle2_mined','cycle2_mined','보험업법 제85조·제85조의3 (국가법령정보센터), 손해보험협회 모집종사자 관리시스템(misi.knia.or.kr)','ai_draft','medium','admin'),
('term','모집종사자 결격사유','보험업법 제84조 제2항에 따라 보험설계사가 될 수 없는 사유. 1) 이 법 또는 금융소비자보호법에 따라 벌금 이상의 형을 선고받고 그 집행이 끝나거나 면제된 날부터 2년이 지나지 아니한 자, 2) 이 법 또는 금융소비자보호법에 따라 금고 이상의 형의 집행유예를 선고받고 유예기간 중에 있는 자, 3) 보험설계사·보험대리점 또는 보험중개사의 등록이 취소된 후 2년이 지나지 아니한 자, 4) 등록취소 처분을 2회 이상 받은 경우 최종 취소일부터 3년이 지나지 아니한 자 등이 해당한다. 결격사유 해소 전까지 모집 업무 수행이 금지된다.','판매',array['결격사유','설계사등록제한','등록취소','보험업법84조'],'cycle2_mined','cycle2_mined','보험업법 제84조 제2항 (국가법령정보센터)','ai_draft','high','admin'),
('term','보험안내자료','보험회사 또는 모집종사자가 보험계약 체결을 권유하거나 보험 상품을 홍보하기 위해 제작·배포하는 서면·전자문서·영상 등의 자료. 보험업법 제95조 및 보험업감독규정에 따라 보험회사는 안내자료 심사·관리번호 부여·심사기록 유지 의무가 있으며, 사실과 다른 내용·과장·비교 기준 불명확 등의 표현은 금지된다.','판매',array['보험안내자료','광고심사','과장광고금지','모집자료'],'cycle2_mined','cycle2_mined','보험업법 제95조, 보험업감독규정 (국가법령정보센터)','ai_draft','high','admin'),
('term','절판마케팅','보험상품 판매 중단(절판) 또는 보험료 인상이 임박했다고 과장·허위로 강조하여 소비자의 즉각적 계약 체결을 유도하는 불건전 영업 행위. 금융감독원은 보험업법 제97조 금지행위 및 금융소비자보호법상 부당권유 금지 규정 위반으로 보고 모니터링·시정 조치를 해왔다.','판매',array['절판마케팅','부당권유','과장광고','모집질서위반'],'cycle2_mined','cycle2_mined','보험업법 제97조 (국가법령정보센터), 금융소비자 보호에 관한 법률 제21조 (국가법령정보센터)','ai_draft','high','admin'),
('term','보험회사 배상책임(모집)','보험회사가 소속 임직원·설계사·보험대리점이 모집 과정에서 위법행위로 계약자에게 손해를 입힌 경우 지는 손해배상 책임. 금융소비자보호법 제45조에 규정되며(구 보험업법 제102조는 금소법 시행(2021.3.25.)으로 삭제·이관됨), 금융상품판매대리·중개업자 등의 대리·중개 업무 중 발생한 손해에 대해 직접판매업자(보험회사)가 거의 무과실에 가까운 배상책임을 부담한다. 보험회사가 상당한 주의·감독을 기울였음을 입증하지 못하면 면책되지 않는다.','민원',array['모집배상책임','보험회사책임','설명의무위반','금융소비자보호법45조'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제45조 (국가법령정보센터), 대법원 2025다212464 판결','ai_draft','high','admin'),
('term','보험계약 자필서명','보험계약 청약 시 원칙적으로 계약자 또는 피보험자의 자필서명이 필요하며, 자필서명을 대신하거나 제3자로 하여금 서명하게 하는 것은 보험업법 제97조 금지행위다. 공인전자서명 또는 보험업감독규정 제4-37조의 요건을 갖춘 수단은 자필서명을 대체할 수 있다.','계약',array['자필서명','대리서명금지','전자서명','청약서'],'cycle2_mined','cycle2_mined','보험업법 제97조, 보험업감독규정 제4-37조 (국가법령정보센터)','ai_draft','high','admin'),
('term','타인의 사망보험 피보험자 동의','타인의 사망을 보험사고로 하는 생명보험계약을 체결할 때 반드시 그 타인(피보험자)의 서면 동의를 받아야 하는 강행규정. 상법 제731조에 근거하며, 동의 없이 체결된 계약은 무효다. 동의는 각 보험계약에 대해 개별적·서면으로 이루어져야 하며, 포괄적 동의 또는 묵시적 동의는 인정되지 않는다. 또한 계약 성립 이후 피보험자가 추인하더라도 무효인 계약은 유효로 되지 않는다. 도박보험 위험성과 피보험자 살해 위험성 방지가 입법 취지다.','계약',array['피보험자동의','타인생명보험','상법731조','서면동의','강행규정'],'cycle2_mined','cycle2_mined','상법 제731조 (국가법령정보센터), 찾기쉬운 생활법령정보(easylaw.go.kr) 보험계약 체결 시 유의사항','ai_draft','high','admin'),
('term','보험 공정경쟁협정','생명보험협회 또는 손해보험협회가 회원사 간 과당경쟁 방지와 건전한 모집질서 유지를 위해 운영하는 자율 협정. 손해보험의 경우 ''손해보험 공정경쟁질서유지에 관한 상호협정''이 정식 명칭이며, 협정 위반 시 협회 차원의 제재가 가능하다. 부당모집행위 조사·처리 및 모집질서문란 신고센터 운영 업무도 각 협회가 담당한다.','판매',array['공정경쟁협정','모집질서','협회협정','과당경쟁방지','모집질서문란신고'],'cycle2_mined','cycle2_mined','생명보험협회(klia.or.kr) 공정경쟁질서 유지 협정, 손해보험협회(knia.or.kr) 손해보험 공정경쟁질서유지에 관한 상호협정','ai_draft','high','admin'),
('term','준법감시인(보험회사)','보험회사가 내부통제기준의 준수 여부를 점검하고 위반사항을 감사·감사위원회에 보고하기 위해 선임하는 임원. 보험업법 제17조에 따라 보험회사는 1인 이상의 준법감시인을 두어야 한다. GA(법인보험대리점)의 경우, 소속 보험설계사 수가 일정 규모(100인) 이상이면 보험업감독규정에 따라 내부통제 담당자 선임 의무가 적용된다. 다만 GA의 준법감시인 의무는 보험업법 제17조가 직접 적용되는 것이 아니라 감독규정 차원에서 규율된다.','판매',array['준법감시인','내부통제','보험업법17조','감사보고','GA내부통제'],'cycle2_mined','cycle2_mined','보험업법 제17조 (국가법령정보센터), 보험업감독규정','ai_draft','medium','admin'),
('term','모집정보조회시스템','생명보험협회 및 손해보험협회(misi.knia.or.kr)가 운영하는 시스템으로, 보험설계사의 등록·말소 이력, 소속사, 자격시험 합격 여부 등을 조회할 수 있다. 보험회사 또는 GA가 설계사 위촉 전 결격사유·과거 제재 이력 확인에 활용된다. 손해보험협회 시스템(misi.knia.or.kr)에서는 설계사 이력 조회, 인터넷 말소신청, 자격시험 신청 결과 조회 등이 가능하다.','판매',array['모집정보조회시스템','설계사이력조회','등록이력','협회시스템','말소이력'],'cycle2_mined','cycle2_mined','손해보험협회 모집종사자 시스템(misi.knia.or.kr), 생명보험협회(klia.or.kr) 모집종사자 정보 시스템','ai_draft','high','admin'),
('term','보험 비교·추천 플랫폼','여러 보험회사의 온라인 상품을 한 곳에서 비교·추천하는 플랫폼. 생명·손해보험협회가 공동 운영하는 ''보험다모아(e-insmarket.or.kr)''와 혁신금융서비스로 지정된 민간 핀테크 플랫폼(네이버, 카카오, 토스 등 11개사)이 있다. 금융위원회는 2024년 1월 핀테크 플랫폼을 통한 보험 비교·추천 서비스를 공식 출시하였으며, 플랫폼 수수료 공시·쏠림 판매 규제가 강화되고 있다.','판매',array['비교추천플랫폼','보험다모아','핀테크보험','CM상품','혁신금융서비스'],'cycle2_mined','cycle2_mined','금융위원회 보도자료(fsc.go.kr), 보험다모아(e-insmarket.or.kr)','ai_draft','medium','admin'),
('term','판매수수료 비교공시','금융위원회가 2026년 1월 의결·3월 시행한 제도로, 보험회사와 보험대리점의 상품별 판매수수료 정보를 공시하도록 의무화한 것. 대형 GA 소속 설계사가 소비자에게 수수료 등급·순위를 비교 설명하도록 하는 의무(GA 비교설명 의무)는 2026년 7월부터 시행된다. 소비자의 알권리 제고와 수수료 중심 판매 편향 방지가 목적이다.','판매',array['수수료공시','비교공시','GA비교설명','판매수수료투명성','2026년시행'],'cycle2_mined','cycle2_mined','금융위원회 보험판매수수료 개편 방안 보도자료(fsc.go.kr, 2026.01), 보험업감독규정','ai_draft','medium','admin'),
('term','금소법 6대 판매원칙(보험)','금융소비자 보호에 관한 법률(금소법)이 보험 모집에 적용하는 6대 판매원칙: 적합성원칙·적정성원칙·설명의무·불공정영업행위 금지·부당권유 금지·광고규제. 적합성원칙(제17조)은 판매자가 소비자에게 부적합한 상품을 ''권유''하는 것을 금지하며, 적정성원칙(제18조)은 소비자가 ''자발적으로 구매''하려 할 때도 부적합하면 이를 고지해야 하는 의무가 생긴다. 두 원칙은 권유 여부로 구분된다.','판매',array['금소법6대원칙','적합성원칙','적정성원칙','부당권유금지','설명의무'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제17조~제22조 (국가법령정보센터)','ai_draft','high','admin'),
('term','보험 모집질서 위반 행정제재','보험업법 위반 모집행위에 대한 행정제재 종류. 보험설계사에게는 업무정지(최대 6개월), 등록취소가 가능하다. 1회 등록취소 후에는 2년간 재등록이 금지되며, 등록취소를 2회 이상 받으면 최종 취소일로부터 3년간 재등록이 금지된다(보험업법 제84조 제2항 제5호·제8호). 보험회사에게는 과징금·기관경고·시정명령이 부과될 수 있다. 행정처분 근거는 보험업법 제84조·제85조이며, 제196조~제205조는 형사 벌칙·과태료 조항으로 행정처분과 구분된다.','민원',array['행정제재','업무정지','등록취소','과징금','재등록금지2년3년'],'cycle2_mined','cycle2_mined','보험업법 제84조·제85조 (국가법령정보센터)','ai_draft','medium','admin'),
('term','시책비','보험회사 또는 GA가 설계사의 실적을 장려하기 위해 기본 모집수수료 외에 추가로 지급하는 성과 장려금. 2026년 7월부터 1200% 룰 적용 대상이 GA 소속 설계사에게 GA가 지급하는 시책비까지 확대되며, 정착지원금·시책비 등을 포함한 수수료 총량이 초과될 경우 지급이 금지된다. 다만, GA의 준법관리 비용 등 일부 운영비(월 보험료의 약 3% 이내)는 적용 예외로 인정될 수 있다.','판매',array['시책비','장려금','1200%룰','수수료총량','GA규제','2026개편'],'cycle2_mined','cycle2_mined','금융위원회 보도자료 ''보험 판매수수료를 분급체계로 개편'' (fsc.go.kr, 2025~2026) / 보험업감독규정 (국가법령정보센터)','ai_draft','high','admin'),
('term','유지수수료(유지관리수수료)','계약 유지 기간에 따라 설계사에게 분할 지급되는 수수료로, 수수료 분급제 도입의 핵심 구성 요소. 금융위원회 보험판매수수료 개편 방안에 따라 기존 최대 3년이던 수수료 분할지급 기간이 최대 7년으로 확대되고, 계약 유지 기간이 길수록 총 수령액이 늘어나는 구조의 유지관리수수료(매년 계약체결비용의 0.8% 이내)가 신설된다. 세부 단계별 시행 일정(2027년 4년→2029년 7년)은 향후 규정 개정 확정 후 확인이 필요하다.','판매',array['유지수수료','분급수수료','장기유지수수료','판매수수료개편','7년분급'],'cycle2_mined','cycle2_mined','금융위원회 보도자료 ''보험 판매수수료를 분급체계로 개편'' (fsc.go.kr, 2025~2026)','ai_draft','medium','admin'),
('term','수수료 공시 의무(보험회사)','2026년 1월부터 보험회사는 채널별(전속·GA·CM 등) 판매수수료율을 보험협회 홈페이지를 통해 공시해야 한다. 선지급 수수료와 유지관리 수수료 비중도 세부 공시 대상이며, 소비자가 동일 보장의 채널별 수수료 차이를 확인해 합리적 선택을 할 수 있도록 하는 투명성 강화 조치다. 500인 이상 설계사를 보유한 GA는 소속 보험사 상품 목록 및 추천 상품의 수수료 단계(5단계)와 순위를 소비자에게 설명할 의무도 부과된다.','판매',array['수수료공시의무','채널별공시','보험수수료투명성','2026개편','GA설명의무'],'cycle2_mined','cycle2_mined','금융위원회 보도자료 ''보험 판매수수료 개편 방안'' (fsc.go.kr, 2025) / 보험업감독규정 (국가법령정보센터)','ai_draft','high','admin'),
('term','보험 모집행위','보험계약의 체결을 권유하거나 이를 위한 설명·상담 등 계약 체결에 실질적으로 영향을 미치는 행위 전반을 의미한다. 보험업법 제2조 제12호에서 ''모집''을 정의하며, 보험설계사·보험대리점·보험중개사·보험회사 임직원만이 모집행위를 할 수 있고, 무자격자의 모집행위는 보험업법 제102조 등 벌칙 조항에 따라 형사처벌 대상이다.','판매',array['보험모집행위','모집종사자','무자격모집금지','보험업법2조12호','모집자격'],'cycle2_mined','cycle2_mined','보험업법 제2조 제12호 (국가법령정보센터) / 보험업법 벌칙 조항','ai_draft','high','admin'),
('term','보험계약 승낙·거절 통지의무','보험회사는 청약을 받으면 30일(신체검사가 필요한 경우 그 검사를 받은 날부터 30일) 이내에 승낙 여부를 계약자에게 통지해야 한다. 기간 내 통지하지 않으면 승낙한 것으로 간주되며, 거절통지 없이 기간 도과 시 보험회사가 책임을 진다. 상법 제638조의2에 근거한다.','계약',array['승낙통지의무','청약승낙','30일이내통지','상법638조의2','자동승낙간주'],'cycle2_mined','cycle2_mined','상법 제638조의2 (국가법령정보센터) / 법제처 찾기쉬운 생활법령 보험계약 체결 및 책임개시시기 (easylaw.go.kr)','ai_draft','high','admin'),
('term','보험계약 비교설명 의무(금소법)','금융소비자보호법 제19조에 따라 금융상품판매업자는 일반금융소비자에게 계약 체결을 권유하거나 소비자가 설명을 요청하는 경우, 금융상품의 중요한 사항을 소비자가 이해할 수 있도록 설명해야 하는 의무. 보장성 상품의 경우 보험료, 보험금 지급제한사유·지급절차, 위험보장 범위 등이 주요 설명 대상이다. 소비자가 이해했음을 확인하는 서명을 받아야 하며, 위반 시 손해배상책임을 진다. 다만 ''비교설명''은 제19조의 독립 조항이 아니라 중요사항 설명의무의 일환으로 실무적으로 적용된다.','판매',array['설명의무','금소법19조','중요사항설명','보장성상품','판매원칙'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제19조 (국가법령정보센터) / 법제처 찾기쉬운 생활법령 금융상품 6대 판매원칙 (easylaw.go.kr)','ai_draft','medium','admin'),
('term','보험금 가지급제도','보험회사가 보험금 지급사유 조사·확인을 위해 약관상 지급기일 이내에 보험금을 지급하지 못할 것으로 예상되는 경우, 추정 보험금의 50% 이내를 우선 지급하는 제도다. 생명보험 표준약관 및 질병상해보험 표준약관(보험업감독업무시행세칙 별표15)에 규정되어 있으며, 보험회사는 지급 지연 사유와 지급예정일(서류 접수일로부터 30 영업일 이내), 가지급 가능 사실을 피보험자 또는 보험수익자에게 즉시 통지해야 한다.','민원',array['가지급','보험금선지급','지급지연','추정보험금50%','표준약관'],'cycle2_mined','cycle2_mined','보험업감독업무시행세칙 별표15 생명보험·질병상해보험 표준약관 (금융감독원, 국가법령정보센터)','ai_draft','high','admin'),
('term','소멸시효 기산점','보험금청구권 소멸시효의 시작점으로, 대법원은 원칙적으로 ''보험사고가 발생한 때''를 기산점으로 본다. 다만 보험사고 발생 여부가 객관적으로 불명확하여 보험금청구권자가 과실 없이 그 발생을 알 수 없었던 경우에는, 보험사고 발생 시점부터 소멸시효를 기산하면 청구권자에게 가혹한 결과를 초래하므로 ''청구권자가 보험사고의 발생을 알았거나 알 수 있었던 때''부터 시효가 진행한다고 보는 것이 대법원의 확립된 입장이다.','민원',array['기산점','소멸시효','보험사고발생일','객관적인식가능성','대법원판례'],'cycle2_mined','cycle2_mined','대법원 2006. 1. 26. 선고 2004다19104 판결 등 (대법원 판례속보, scourt.go.kr) / 법제처 찾기쉬운 생활법령 보험금청구권 소멸시효 (easylaw.go.kr)','ai_draft','high','admin'),
('term','보험금 지급지연이자','보험자가 약관상 지급기일을 초과하여 보험금을 지급할 경우 가산하는 이자다. 생명보험·질병상해보험 표준약관(보험업감독업무시행세칙 별표15)에 따르면, 지급기일 다음날부터 지급일까지 약관대출이율을 기본으로, 31~60일 초과 시 약관대출이율+연 4%, 61~90일 초과 시 약관대출이율+연 6%, 91일 이후 약관대출이율+연 8%를 추가 적용한다. 소송 판결 선고 이후에는 소송촉진 등에 관한 특례법상 이율이 적용된다.','민원',array['지연이자','지급지연','지연손해금','보험금이자','약관대출이율','표준약관'],'cycle2_mined','cycle2_mined','보험업감독업무시행세칙 별표15 생명보험·질병상해보험 표준약관 (금융감독원, 국가법령정보센터) / 상법 제658조 (국가법령정보센터)','ai_draft','high','admin'),
('term','자기손해사정','보험계약자·피보험자가 보험회사가 선임한 손해사정사의 사정 결과에 불복하거나 별도 사정이 필요한 경우 직접 손해사정사를 선임하는 제도다(보험업법 제185조). 보험회사가 사고 통보를 받은 날부터 7일 이내에 정당한 사유 없이 손해사정에 착수하지 않은 경우, 또는 보험회사가 소비자의 별도 선임 요청에 동의한 경우에 직접 선임이 가능하다. 보험회사가 동의한 경우에 한해 관련 수수료를 보험회사가 부담하며, 이미 완료된 사정 결과에 불복하여 다시 선임하는 경우에는 계약자가 비용을 부담한다.','민원',array['자기손해사정','손해사정사선임','독립손해사정','소비자선임','보험업법185조'],'cycle2_mined','cycle2_mined','보험업법 제185조 (국가법령정보센터) / 금융위원회 보도자료 ''소비자의 손해사정사 선임 활성화'' (fsc.go.kr)','ai_draft','medium','admin'),
('term','손해사정 위탁','보험회사가 보험사고로 인한 손해액 및 보험금의 사정 업무를 손해사정사 또는 손해사정업자에게 맡기는 행위다(보험업법 제185조). 보험회사는 손해사정업자 선정기준 등을 포함한 업무위탁기준을 마련해야 하며, 자회사 등 특정 손해사정업자에게 전체 손해사정 업무의 50% 이상을 위탁할 경우 위탁 선정·평가기준을 이사회에 보고하고 인터넷 홈페이지에 공시하여야 한다.','민원',array['손해사정위탁','보험업법185조','손해사정업자','위탁기준','이사회보고공시'],'cycle2_mined','cycle2_mined','보험업법 제185조 (국가법령정보센터) / 금융위원회 ''손해사정 업무위탁 등에 관한 모범규준 개정'' (fsc.go.kr)','ai_draft','high','admin'),
('term','분쟁조정 효력 (재판상화해)','금융분쟁조정위원회의 조정안을 양 당사자가 수락하면 재판상 화해와 동일한 효력이 발생한다(금융소비자 보호에 관한 법률 제39조). 이는 확정판결과 동일한 효력으로, 당사자가 이행하지 않을 경우 집행문을 부여받아 강제집행이 가능하다. 조정결정 통보를 받은 날로부터 20일 이내에 수락서를 제출하여야 조정이 성립한다.','민원',array['재판상화해','분쟁조정효력','금소법39조','확정판결동일','강제집행'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제39조 (국가법령정보센터) / 금융감독원 분쟁조정절차 안내(fss.or.kr)','ai_draft','high','admin'),
('term','분쟁조정 소멸시효 중단','금융분쟁조정위원회에 분쟁조정을 신청하면 소멸시효 중단 효력이 발생한다(금융소비자 보호에 관한 법률 제40조). 다만 합의권고를 하지 않거나 조정위원회에 회부되지 않는 경우에는 시효중단 효력이 인정되지 않는다. 이 경우 1개월 이내에 재판상 청구 등 조치를 취하면 최초 신청 시점으로 소급하여 시효가 중단된 것으로 본다.','민원',array['시효중단','분쟁조정신청','금소법40조','소멸시효','1개월내재청구'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제40조 (국가법령정보센터) / 보험연구원 이슈보고서 2021-22','ai_draft','high','admin'),
('term','편면적 구속력','금융분쟁조정위원회의 조정안에 금융소비자가 동의하면 금융회사는 의무적으로 이를 수용해야 하는 제도를 말한다. 소액 금융분쟁(금소법 제42조상 2,000만 원 이하) 조정 사건에서 소비자 측의 수락만으로 금융회사에 이행 의무를 부과하는 방식이 논의되고 있으나, 2026년 현재 금소법에는 아직 법제화되지 않았으며 국회 개정 논의가 진행 중이다. 현행 금소법 제39조상 조정 효력은 양 당사자 모두 수락할 때에만 발생한다.','민원',array['편면적구속력','분쟁조정','소액분쟁','2000만원이하','금융회사의무','금소법42조'],'cycle2_mined','cycle2_mined','금융소비자 보호에 관한 법률 제39조·제42조 (국가법령정보센터) / 금융소비자보호법상 분쟁민원 해결과 편면적 구속력에 대한 법적 연구 (KCI, 한국외국어대학교 법학연구소)','ai_draft','medium','admin'),
('term','자살면책 2년 조항','생명보험 표준약관은 책임개시일로부터 2년 이내에 피보험자가 자살한 경우 보험금을 지급하지 않으나, 2년 경과 후 자살한 경우에는 일반 사망보험금을 지급한다. 재해사망특약에서 별도로 ''2년 경과 후 자살 시 재해사망보험금 지급''을 규정한 경우에는 재해사망보험금도 지급될 수 있다(대법원 판례 확인). 단, 피보험자가 정신질환 등으로 자유로운 의사결정을 할 수 없는 상태에서 사망한 경우는 자살로 보지 않아 면책이 적용되지 않는다.','보장',array['자살면책','2년','자유로운의사결정','정신질환','사망보험금','재해사망특약'],'cycle2_mined','cycle2_mined','생명보험 표준약관 (보험업감독업무시행세칙 별표15, 금융감독원) / 상법 제732조의2 (국가법령정보센터) / 생명보험협회 자료 (klia.or.kr)','ai_draft','medium','admin'),
('term','고의사고 면책','보험사고가 보험계약자, 피보험자 또는 보험수익자의 고의 또는 중대한 과실로 발생한 경우 보험자는 보험금 지급 책임이 없다(상법 제659조). 단, 사망 또는 상해를 보험사고로 하는 인보험(생명보험·상해보험)에서는 중대한 과실로 인한 사고에 대해 면책을 적용할 수 없으며(상법 제732조의2, 제739조), 고의 또는 고의에 준하는 행위로 인한 경우에만 면책이 인정된다(대법원 판례).','보장',array['고의사고','면책','상법659조','중과실','상법732조의2','인보험'],'cycle2_mined','cycle2_mined','상법 제659조·제732조의2·제739조 (국가법령정보센터)','ai_draft','high','admin'),
('term','계약해지와 보험금청구권 소멸','보험사고 발생 후라도 보험자가 고지의무위반·통지의무위반 등을 이유로 계약을 해지하면 원칙적으로 보험금 지급 책임이 소멸하며, 이미 지급한 보험금의 반환 청구도 가능하다(상법 제655조 본문). 다만 의무위반 사실이 보험사고 발생에 영향을 미치지 않았음이 증명되면 보험금을 지급해야 한다(상법 제655조 단서). 이 인과관계 부존재에 대한 증명책임은 보험계약자 측에 있다(대법원 판례).','민원',array['해지후보험금','상법655조','소급면책','인과관계','증명책임'],'cycle2_mined','cycle2_mined','상법 제655조 (국가법령정보센터) / 대법원 판례 (국가법령정보센터)','ai_draft','high','admin'),
('term','고지의무위반 인과관계','보험계약자가 고지의무를 위반한 사실과 보험사고 발생 사이에 인과관계가 없다는 점(즉, 위반 사실이 보험사고에 영향을 미치지 않았다는 점)은 보험계약자 측이 증명해야 한다(상법 제655조 단서, 대법원 2025. 1. 9. 선고 2024다272941 판결). 다만 약관에서 인과관계 부존재 증명책임을 보험자에게 부과하기로 특별히 규정한 경우 그 약관이 우선 적용된다.','인수',array['고지의무위반','인과관계','입증책임','상법655조단서','대법원2025'],'cycle2_mined','cycle2_mined','상법 제655조 단서 (국가법령정보센터) / 대법원 2025. 1. 9. 선고 2024다272941 판결 (대법원 판례속보)','ai_draft','high','admin'),
('term','고지의무위반 해지권 제척기간','보험자의 고지의무위반을 이유로 한 계약 해지권은 위반 사실을 안 날로부터 1개월, 계약 체결일로부터 3년이 경과하면 소멸한다(상법 제651조). 이 두 기간 중 먼저 도래하는 기간이 경과하면 해지권이 소멸한다. 단, 보험자가 계약 당시 위반 사실을 알았거나 중대한 과실로 알지 못한 경우에는 해지권이 처음부터 발생하지 않는다.','인수',array['제척기간','해지권','상법651조','3년1개월','고지의무'],'cycle2_mined','cycle2_mined','상법 제651조 (국가법령정보센터)','ai_draft','high','admin'),
('term','감액지급기간','보험 가입 후 일정 기간 동안 보험사고가 발생해도 약정 보험금의 일부(예: 50%)만 지급하는 기간을 말한다. 면책기간(보험금 전혀 미지급)과 달리 일부 보장이 이루어진다는 점에서 구분된다. 주로 암보험·치아보험 등 도덕적 해이 위험이 높은 상품에서 각 사 약관으로 설정되며, 구체적인 감액 비율과 기간은 상품별 약관에 따라 다르다.','보장',array['감액지급기간','감액기간','일부지급','가입초기','면책기간'],'cycle2_mined','cycle2_mined','생명·손해보험 표준약관 (보험업감독업무시행세칙 별표15, 금융감독원) / 금융감독원 금융소비자보호 표준약관 안내(fss.or.kr)','ai_draft','medium','admin'),
('term','부지급·일부지급 통지 의무','보험회사가 보험금 지급을 거절하거나 감액 지급하는 경우, 구체적인 사유와 근거 약관 조항을 서면으로 통지해야 한다. 이 의무의 직접적 근거는 보험업감독규정(금융위원회 고시) 및 보험업감독업무시행세칙(금융감독원 세칙)에 규정되어 있으며, 보험업법에 위임 근거가 있다. 서면 통지 없이 구두로만 부지급 결정을 통보하는 경우 분쟁 시 보험자에게 불리하게 작용할 수 있다.','민원',array['부지급통지','일부지급','서면통지의무','거절사유','보험업감독규정'],'cycle2_mined','cycle2_mined','보험업감독규정·보험업감독업무시행세칙 (국가법령정보센터) / 보험업법 (국가법령정보센터)','ai_draft','medium','admin'),
('term','보험자대위 (청구권대위)','손해가 제3자의 행위로 발생한 경우 보험금을 지급한 보험자는 지급한 금액 한도 내에서 제3자에 대한 피보험자의 손해배상청구권을 취득한다(상법 제682조). 보험자대위의 취지는 피보험자가 보험금과 손해배상금을 이중으로 수령하는 이득을 방지하고, 배상의무자인 제3자가 면책되는 불합리를 제거하기 위함이다. 보험자는 피보험자의 권리를 해치지 않는 범위 내에서만 대위권을 행사할 수 있다.','보장',array['청구권대위','보험자대위','상법682조','구상권','이득금지'],'cycle2_mined','cycle2_mined','상법 제682조 (국가법령정보센터)','ai_draft','high','admin'),
('term','피해자 직접청구권','책임보험에서 피해자는 보험금액 한도 내에서 보험자에게 직접 보상을 청구할 수 있다(상법 제724조 제2항). 이 직접청구권의 법적 성질은 보험자가 피보험자의 손해배상채무를 병존적으로 인수한 것으로서 피해자가 보험자에 대하여 갖는 손해배상청구권이다(대법원 판례). 제3자의 직접청구권은 피보험자의 보험금청구권에 우선하며(상법 제724조 제1항), 보험자는 제3자(피해자)가 피보험자로부터 배상을 받기 전에는 피보험자에 대한 보험금 지급으로써 직접청구권을 행사하는 피해자에게 대항할 수 없다.','보장',array['직접청구권','책임보험','상법724조','피해자청구','병존적채무인수'],'cycle2_mined','cycle2_mined','상법 제724조 제1항·제2항 (국가법령정보센터) / 대법원 판례 (국가법령정보센터)','ai_draft','high','admin');
